/* ─────────────────────────────────────────────────
   TOAST
───────────────────────────────────────────────── */
function Toast({ msg, type, onDone }: { msg:string; type:'ok'|'err'; onDone:()=>void }) {
  useState(() => { const t = setTimeout(onDone, 2600); return () => clearTimeout(t); });
  return (
    <motion.div initial={{ opacity:0, y:-20, x:'-50%' }} animate={{ opacity:1, y:0, x:'-50%' }} exit={{ opacity:0, y:-20, x:'-50%' }}
      style={{ position:'fixed', top:20, left:'50%', zIndex:9999, padding:'11px 22px', borderRadius:12,
        background: type==='ok' ? 'linear-gradient(135deg,#22c55e,#16a34a)' : 'linear-gradient(135deg,#ef4444,#b91c1c)',
        color:'#fff', fontSize:13, fontWeight:700, fontFamily:'Arial,sans-serif',
        boxShadow:'0 4px 24px rgba(0,0,0,0.5)', maxWidth:'90vw', textAlign:'center',
        pointerEvents:'none', letterSpacing:'0.03em' }}>
      {msg}
    </motion.div>
  );
}

/* ─────────────────────────────────────────────────
   PERSISTENT STATE HOOK
   Все данные аккаунта привязаны к хэшу мастер-ключа.
   Хранится в localStorage['swaip_account_${hash}_${key}'].
   Никогда не удаляется при выходе или перезагрузке.
───────────────────────────────────────────────── */
function usePersistedState<T>(
  key: string,
  defaultValue: T,
  hash: string
): [T, React.Dispatch<React.SetStateAction<T>>] {
  const fullKey = `swaip_account_${hash}_${key}`;
  const [value, _setValue] = useState<T>(() => {
    try {
      const stored = localStorage.getItem(fullKey);
      if (stored !== null) {
        const parsed = JSON.parse(stored);
        /* null в localStorage = результат очистки blob: URL. Используем дефолт */
        if (parsed !== null && parsed !== undefined) return parsed as T;
      } else {
        /* Первое использование: сохраняем дефолт в localStorage чтобы он попал на сервер */
        const notEmpty = defaultValue !== null && defaultValue !== undefined &&
          defaultValue !== '' && !(Array.isArray(defaultValue) && (defaultValue as unknown[]).length === 0);
        if (notEmpty) {
          try { localStorage.setItem(fullKey, JSON.stringify(defaultValue)); } catch {}
        }
      }
      return defaultValue;
    } catch { return defaultValue; }
  });
  const setValue: React.Dispatch<React.SetStateAction<T>> = (action) => {
    _setValue(prev => {
      const next = typeof action === 'function'
        ? (action as (prev: T) => T)(prev)
        : action;
      try { localStorage.setItem(fullKey, JSON.stringify(next)); } catch {}
      return next;
    });
  };
  return [value, setValue];
}

/* ─────────────────────────────────────────────────
   LOGIN SCREEN
───────────────────────────────────────────────── */
function usePWAInstall() {
  /* Берём событие из глобала — захваченного ДО старта React в index.html */
  const [prompt, setPrompt] = useState<any>(() => (window as any).__pwaInstallPrompt ?? null);
  const [isIOS, setIsIOS] = useState(false);
  const [isInstalled, setIsInstalled] = useState(false);

  useEffect(() => {
    setIsInstalled(window.matchMedia('(display-mode: standalone)').matches || (navigator as any).standalone === true);
    setIsIOS(/iphone|ipad|ipod/i.test(navigator.userAgent) && !(navigator as any).standalone);
    /* Если событие уже есть в глобале — используем */
    if ((window as any).__pwaInstallPrompt) setPrompt((window as any).__pwaInstallPrompt);
    /* Слушаем и на будущее (повторный визит и т.д.) */
    const handler = (e: Event) => {
      e.preventDefault();
      (window as any).__pwaInstallPrompt = e;
      setPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const install = async () => {
    if (!prompt) return;
    prompt.prompt();
    const { outcome } = await prompt.userChoice;
    if (outcome === 'accepted') setIsInstalled(true);
    (window as any).__pwaInstallPrompt = null;
    setPrompt(null);
  };

  return { prompt, isIOS, isInstalled, install };
}

/* ── Серьёзный звук подтверждения (низкие тона, без яркости) ── */
function playDing() {
  try {
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const now = ctx.currentTime;
    const tone = (freq: number, start: number, dur: number, vol = 0.18) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.setValueAtTime(freq, now + start);
      osc.connect(gain); gain.connect(ctx.destination);
      gain.gain.setValueAtTime(0, now + start);
      gain.gain.linearRampToValueAtTime(vol, now + start + 0.04);
      gain.gain.setValueAtTime(vol, now + start + dur * 0.7);
      gain.gain.exponentialRampToValueAtTime(0.0001, now + start + dur);
      osc.start(now + start);
      osc.stop(now + start + dur);
    };
    /* Два мягких баритональных тона: «подтверждено» */
    tone(330, 0,    0.42, 0.16);
    tone(440, 0.18, 0.55, 0.20);
    setTimeout(() => { try { ctx.close(); } catch {} }, 1100);
  } catch {}
}

/* ── Звук «ключ сгенерирован» — глубокий низкий «бам», предупреждение ── */
function playKeyRevealSound() {
  try {
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const now = ctx.currentTime;
    /* Низкий «удар» — обращает внимание */
    const osc1 = ctx.createOscillator(); const g1 = ctx.createGain();
    osc1.type = 'sine'; osc1.frequency.setValueAtTime(110, now);
    osc1.frequency.exponentialRampToValueAtTime(55, now + 0.6);
    g1.gain.setValueAtTime(0, now);
    g1.gain.linearRampToValueAtTime(0.32, now + 0.03);
    g1.gain.exponentialRampToValueAtTime(0.0001, now + 0.7);
    osc1.connect(g1); g1.connect(ctx.destination);
    osc1.start(now); osc1.stop(now + 0.75);
    /* Сверху — спокойный синусоидный «гул» */
    const osc2 = ctx.createOscillator(); const g2 = ctx.createGain();
    osc2.type = 'sine'; osc2.frequency.setValueAtTime(220, now + 0.05);
    g2.gain.setValueAtTime(0, now + 0.05);
    g2.gain.linearRampToValueAtTime(0.12, now + 0.15);
    g2.gain.exponentialRampToValueAtTime(0.0001, now + 0.8);
    osc2.connect(g2); g2.connect(ctx.destination);
    osc2.start(now + 0.05); osc2.stop(now + 0.85);
    setTimeout(() => { try { ctx.close(); } catch {} }, 1200);
  } catch {}
}

/* ── Время суток для приветствия ── */
function getTimeOfDay(): string {
  const h = new Date().getHours();
  if (h >= 5 && h < 12) return 'Доброе утро';
  if (h >= 12 && h < 17) return 'Добрый день';
  if (h >= 17) return 'Добрый вечер';
  return 'Доброй ночи';
}

/* ── Склонение в винительный падеж (для названий услуг) ── */
function ruAcc(text: string): string {
  if (!text) return text;
  const words = text.trim().split(/\s+/);
  const w = words[0];
  let d = w;
  if (/ия$/i.test(w)) d = w.slice(0, -2) + 'ию';
  else if (/я$/i.test(w)) d = w.slice(0, -1) + 'ю';
  else if (/а$/i.test(w)) d = w.slice(0, -1) + 'у';
  words[0] = d.charAt(0).toLowerCase() + d.slice(1);
  return words.join(' ');
}

/* ── 20 шаблонов от «Алины» (рандомный выбор при каждом открытии чата) ── */
type _BookingTpl = {
  gr(t: string, a: string): string;
  an(n: string): string;
  ap(n: string, ph: string, when: string, svc: string): string;
  ac(n: string, when: string, svc: string): string;
};
/* ── Форматирование слота на живом русском языке ── */
function formatSlotRu(slot: string): string {
  const d = new Date(slot.replace(' ', 'T'));
  const inDay = ['в воскресенье','в понедельник','во вторник','в среду','в четверг','в пятницу','в субботу'];
  const months = ['января','февраля','марта','апреля','мая','июня','июля','августа','сентября','октября','ноября','декабря'];
  const time = (slot.split(' ')[1] || '').substring(0, 5);
  return `${inDay[d.getDay()]}, ${d.getDate()} ${months[d.getMonth()]} в ${time}`;
}

