function getInviteTexts(mode: string) {
  return mode === 'pro' ? INVITE_TEXTS_PRO : INVITE_TEXTS_SCENE;
}

/* Оставляем для совместимости */
const INVITE_TEXTS = [
  (_:string, __:string, link:string) => INVITE_TEXTS_PRO[0](link),
];

function InviteModal({
  mode, userHash, onClose, customCode,
}: { mode: keyof typeof INVITE_CONFIG; userHash: string; onClose: () => void; customCode?: string }) {
  const cfg = INVITE_CONFIG[mode];
  const { t } = useLang();
  const modeSlug = mode === 'circle' ? 'krug' : mode;
  /* Короткая ссылка на основе 9-значного кода (вместо 64-символьного хеша) */
  const modeForCode = modeSlug as 'pro' | 'scene' | 'krug';
  const shortPrefix = modeSlug === 'pro' ? 'p' : modeSlug === 'scene' ? 's' : 'k';
  const inviteCode = (modeForCode === 'pro' && customCode) ? customCode : computeInviteCode(userHash, modeForCode);
  const link = `${APP_BASE}/${shortPrefix}/${inviteCode}`;

  const texts = getInviteTexts(mode);

  const [tplIdx,    setTplIdx]    = useState(() => Math.floor(Math.random() * texts.length));
  const [imgIdx]    = useState(() => Math.floor(Math.random() * cfg.imgs.length));
  const [withImg,   setWithImg]   = useState(true);
  const [copied,    setCopied]    = useState(false);
  const [shuffled,  setShuffled]  = useState(false);
  const [customImg, setCustomImg] = useState<string|null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => setCustomImg(reader.result as string);
    reader.readAsDataURL(file);
  };

  const shuffle = () => {
    let next = Math.floor(Math.random() * texts.length);
    if (next === tplIdx && texts.length > 1) next = (next + 1) % texts.length;
    setTplIdx(next);
    setShuffled(true);
    setTimeout(() => setShuffled(false), 600);
  };

  const inviteText = texts[tplIdx](link);
  const encodedText = encodeURIComponent(inviteText);
  const encodedLink = encodeURIComponent(link);

  const shareUrls: Record<string, string> = {
    telegram: `https://t.me/share/url?url=${encodedLink}&text=${encodeURIComponent(inviteText)}`,
    vk:       `https://vk.com/share.php?url=${encodedLink}&title=${encodedText}`,
    whatsapp: `https://api.whatsapp.com/send?text=${encodeURIComponent(inviteText)}`,
  };

  const copyAll = async () => {
    await navigator.clipboard.writeText(inviteText).catch(() => {});
    setCopied(true); setTimeout(() => setCopied(false), 2200);
  };

  return (
    <AnimatePresence>
      <>
        {/* overlay */}
        <motion.div initial={{ opacity:0 }} animate={{ opacity:1 }} exit={{ opacity:0 }}
          onClick={onClose}
          style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.8)',
            backdropFilter:'blur(8px)', zIndex:1000 }} />

        {/* sheet */}
        <motion.div initial={{ y:'100%' }} animate={{ y:0 }} exit={{ y:'100%' }}
          transition={{ type:'spring', stiffness:360, damping:34 }}
          style={{ position:'fixed', bottom:0, left:0, right:0, zIndex:1001,
            background:'rgba(12,12,20,0.99)', backdropFilter:'blur(28px)',
            borderRadius:'28px 28px 0 0', border:'1px solid rgba(255,255,255,0.09)',
            paddingBottom:'env(safe-area-inset-bottom,16px)' }}>

          {/* ── Ручка ── */}
          <div style={{ width:40, height:4, background:'rgba(255,255,255,0.15)',
            borderRadius:99, margin:'14px auto 0' }} />

          {/* ── Заголовок ── */}
          <div style={{ padding:'16px 20px 0', display:'flex', alignItems:'center', gap:10 }}>
            <div style={{ width:44, height:44, borderRadius:'50%', flexShrink:0,
              background:cfg.bg, border:`2px solid ${cfg.color}44`,
              display:'flex', alignItems:'center', justifyContent:'center', fontSize:22 }}>
              {cfg.emoji}
            </div>
            <div style={{ flex:1 }}>
              <p style={{ margin:0, fontWeight:900, fontSize:15,
                fontFamily:'"Montserrat",sans-serif', color:'#fff' }}>
                {t.invite_to_swaip}
              </p>
              <p style={{ margin:0, fontSize:12, color:'rgba(255,255,255,0.45)' }}>
                {t.invite_account} «{t[cfg.labelKey] ?? cfg.label}» · {link.replace('https://','').slice(0,26)}…
              </p>
            </div>
            <motion.button whileTap={{ scale:0.93 }} onClick={onClose}
              style={{ display:'flex', alignItems:'center', gap:5, padding:'7px 14px',
                background:'rgba(255,255,255,0.07)', border:'1px solid rgba(255,255,255,0.12)',
                borderRadius:50, cursor:'pointer', color:'rgba(255,255,255,0.7)',
                fontSize:12, fontWeight:700, fontFamily:'"Montserrat",sans-serif',
                flexShrink:0 }}>
              <span style={{ fontSize:14 }}>←</span> {t.back}
            </motion.button>
          </div>

          {/* ── Превью карточки ── */}
          <div style={{ margin:'14px 20px 0', borderRadius:18, overflow:'hidden',
            border:`1px solid ${cfg.color}33`,
            boxShadow:`0 0 24px ${cfg.glow}` }}>
            {withImg && (
              <div style={{ height:160, position:'relative', overflow:'hidden' }}>
                <img src={customImg ?? cfg.imgs[imgIdx]} alt="" draggable={false}
                  style={{ width:'100%', height:'100%', objectFit:'cover' }} />
                <div style={{ position:'absolute', inset:0,
                  background:'linear-gradient(to bottom,transparent 30%,rgba(0,0,0,0.85) 100%)' }} />
                <div style={{ position:'absolute', bottom:12, left:14, right:14 }}>
                  <div style={{ display:'inline-flex', alignItems:'center', gap:6,
                    background:cfg.bg, borderRadius:99, padding:'4px 12px 4px 8px',
                    border:`1px solid ${cfg.color}55`, marginBottom:6 }}>
                    <span style={{ fontSize:14 }}>{cfg.emoji}</span>
                    <span style={{ fontSize:11, fontWeight:800, color:cfg.color,
                      fontFamily:'"Montserrat",sans-serif', letterSpacing:'0.06em' }}>
                      SWAIP · {t[cfg.labelKey] ?? cfg.label}
                    </span>
                  </div>
                </div>
              </div>
            )}
            <motion.div
              key={tplIdx}
              initial={{ opacity:0, y:6 }}
              animate={{ opacity:1, y:0 }}
              transition={{ duration:0.22 }}
              style={{ padding:'12px 14px', background:withImg ? 'rgba(0,0,0,0.9)' : cfg.bg }}>
              <p style={{ margin:0, fontSize:13, lineHeight:1.65,
                color:'rgba(255,255,255,0.9)' }}>{inviteText}</p>
            </motion.div>
          </div>

          {/* ── Кнопка "Другой текст" ── */}
          <div style={{ padding:'10px 20px 0', display:'flex', justifyContent:'center' }}>
            <motion.button
              whileTap={{ scale:0.93 }}
              animate={shuffled ? { scale:[1,1.07,1] } : {}}
              transition={{ duration:0.3 }}
              onClick={shuffle}
              style={{
                display:'flex', alignItems:'center', gap:8,
                padding:'10px 24px', borderRadius:50,
                background:`${cfg.color}18`,
                border:`1.5px solid ${cfg.color}55`,
                color:cfg.color, cursor:'pointer',
                fontFamily:'"Montserrat",sans-serif',
                fontWeight:800, fontSize:13,
              }}>
              {'🔀 '+t.another_text}
              <span style={{ opacity:0.55, fontSize:11, fontWeight:500 }}>
                {tplIdx + 1}/{texts.length}
              </span>
            </motion.button>
          </div>

          {/* ── Скрытый file input ── */}
          <input ref={fileInputRef} type="file" accept="image/*"
            style={{ display:'none' }} onChange={handleFileChange} />

          {/* ── Переключатель С картинкой / Без ── */}
          <div style={{ display:'flex', gap:8, padding:'10px 20px 0' }}>
            {[true, false].map(v => (
              <motion.button key={String(v)} whileTap={{ scale:0.93 }}
                onClick={() => setWithImg(v)}
                style={{ flex:1, padding:'9px 0', borderRadius:14, fontSize:13, fontWeight:700,
                  cursor:'pointer', fontFamily:'"Montserrat",sans-serif',
                  background: withImg===v ? `${cfg.color}22` : 'rgba(255,255,255,0.05)',
                  border: `1px solid ${withImg===v ? cfg.color+'55' : 'rgba(255,255,255,0.1)'}`,
                  color: withImg===v ? cfg.color : 'rgba(255,255,255,0.5)' }}>
                {v ? '🖼 '+t.with_image : '📝 '+t.text_only}
              </motion.button>
            ))}
          </div>

          {/* ── Загрузить своё фото (только при withImg) ── */}
          {withImg && (
            <div style={{ padding:'8px 20px 0', display:'flex', gap:8, alignItems:'center' }}>
              <motion.button whileTap={{ scale:0.93 }}
                onClick={() => fileInputRef.current?.click()}
                style={{ flex:1, padding:'9px 0', borderRadius:14, fontSize:13, fontWeight:700,
                  cursor:'pointer', fontFamily:'"Montserrat",sans-serif',
                  background:'rgba(255,255,255,0.05)',
                  border:'1px solid rgba(255,255,255,0.12)',
                  color:'rgba(255,255,255,0.65)' }}>
                {'📷 '+t.upload_photo}
              </motion.button>
              {customImg && (
                <motion.button whileTap={{ scale:0.9 }}
                  onClick={() => setCustomImg(null)}
                  style={{ padding:'9px 14px', borderRadius:14, fontSize:13, fontWeight:700,
                    cursor:'pointer', background:'rgba(255,80,80,0.12)',
                    border:'1px solid rgba(255,80,80,0.25)', color:'rgba(255,100,100,0.9)' }}>
                  ✕
                </motion.button>
              )}
            </div>
          )}

          {/* ── Поделиться / Копировать ── */}
          <div style={{ padding:'12px 20px 8px', display:'flex', flexDirection:'column', gap:10 }}>

            {/* Нативный системный шаринг (все приложения устройства) */}
            {typeof navigator !== 'undefined' && 'share' in navigator && (
              <motion.button whileTap={{ scale:0.97 }}
                onClick={async () => {
                  try {
                    await navigator.share({ title: 'SWAIP', text: inviteText, url: link });
                  } catch {}
                }}
                style={{ width:'100%', padding:'15px', borderRadius:16, fontSize:15, fontWeight:800,
                  cursor:'pointer', fontFamily:'"Montserrat",sans-serif',
                  display:'flex', alignItems:'center', justifyContent:'center', gap:10,
                  background:`linear-gradient(135deg,${cfg.color}33,${cfg.color}18)`,
                  border:`1px solid ${cfg.color}55`,
                  color:'#fff', boxShadow:`0 4px 20px ${cfg.glow}` }}>
                <span style={{ fontSize:22 }}>↗️</span>
                {t.share}
              </motion.button>
            )}

            {/* Фолбэк: прямые ссылки на соцсети (только если нет navigator.share) */}
            {!(typeof navigator !== 'undefined' && 'share' in navigator) && (
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:10 }}>
                {[
                  { key:'telegram',  label:'Telegram',  icon:'✈️',  color:'#29b6f6' },
                  { key:'vk',        label:'VKontakte', icon:'💙',  color:'#5181b8' },
                  { key:'whatsapp',  label:'WhatsApp',  icon:'💬',  color:'#25d366' },
                ].map(p => (
                  <motion.button key={p.key} whileTap={{ scale:0.91 }}
                    onClick={() => window.open(shareUrls[p.key], '_blank')}
                    style={{ padding:'12px 6px', borderRadius:16,
                      background:`${p.color}18`, border:`1px solid ${p.color}33`,
                      color:p.color, cursor:'pointer', fontWeight:700, fontSize:11,
                      fontFamily:'"Montserrat",sans-serif',
                      display:'flex', flexDirection:'column', alignItems:'center', gap:6 }}>
                    <span style={{ fontSize:24 }}>{p.icon}</span>
                    {p.label}
                  </motion.button>
                ))}
              </div>
            )}

            {/* Копировать текст + ссылку */}
            <motion.button whileTap={{ scale:0.97 }} onClick={copyAll}
              style={{ width:'100%', padding:'14px', borderRadius:16, fontSize:14, fontWeight:700,
                cursor:'pointer', fontFamily:'"Montserrat",sans-serif',
                display:'flex', alignItems:'center', justifyContent:'center', gap:10,
                background: copied ? 'rgba(34,197,94,0.15)' : 'rgba(255,255,255,0.07)',
                border:`1px solid ${copied ? 'rgba(34,197,94,0.4)' : 'rgba(255,255,255,0.12)'}`,
                color: copied ? '#4ade80' : 'rgba(255,255,255,0.85)' }}>
              <span style={{ fontSize:20 }}>{copied ? '✅' : '🔗'}</span>
              {copied ? t.copied : t.copy_text_link}
            </motion.button>
          </div>

          {/* ── Код-приглашения ── */}
          {(() => {
            const invCode = computeInviteCode(userHash, modeSlug as 'pro'|'scene'|'krug');
            return (
              <div style={{ margin:'4px 20px 20px', background:`${cfg.color}0e`,
                border:`1px solid ${cfg.color}33`, borderRadius:16, padding:'12px 16px' }}>
                <p style={{ margin:'0 0 8px', fontSize:11, fontWeight:700, color:`${cfg.color}cc`,
                  fontFamily:'"Montserrat",sans-serif', letterSpacing:0.5, textTransform:'uppercase' }}>
                  🔢 {t.invite_code_label} · {t[cfg.labelKey] ?? cfg.label}
                </p>
                <div style={{ display:'flex', gap:8, alignItems:'center' }}>
                  <span style={{ flex:1, fontFamily:'monospace', fontSize:22, fontWeight:900,
                    letterSpacing:4, color:'#fff', userSelect:'all' }}>
                    {invCode}
                  </span>
                  <motion.button whileTap={{ scale:0.93 }}
                    onClick={() => { navigator.clipboard?.writeText(invCode); }}
                    style={{ padding:'8px 14px', background:`${cfg.color}22`,
                      border:`1px solid ${cfg.color}44`, borderRadius:10,
                      color:cfg.color, fontWeight:700, fontSize:12, cursor:'pointer',
                      fontFamily:'"Montserrat",sans-serif', flexShrink:0 }}>
                    {t.copy_btn}
                  </motion.button>
                </div>
                <p style={{ margin:'6px 0 0', fontSize:11, color:'rgba(255,255,255,0.4)', lineHeight:1.5 }}>
                  {t.invite_code_hint} «{t[cfg.labelKey] ?? cfg.label}»
                </p>
              </div>
            );
          })()}
        </motion.div>
      </>
    </AnimatePresence>
  );
}

/* ══════════════════════════════════════
   SWAIP BRAND STRIP — горизонтальная полоска с металлическим логотипом
   Используется в шапке каждого аккаунта и на аватаре-телевизоре
══════════════════════════════════════ */
function SwaipStrip({ zIndex = 8 }: { zIndex?: number }) {
  return (
    <div style={{ position:'absolute', top:0, left:0, right:0, height:30,
      display:'flex', alignItems:'center', justifyContent:'center',
      zIndex, pointerEvents:'none', overflow:'hidden' }}>
      {/* Полупрозрачная полоска — видна только в центре, затухает по краям */}
      <div style={{ position:'absolute', inset:0,
        background:'linear-gradient(90deg,transparent 0%,rgba(18,18,28,0.72) 22%,rgba(24,24,38,0.88) 50%,rgba(18,18,28,0.72) 78%,transparent 100%)' }} />
      {/* Тонкая горящая линия сверху */}
      <div style={{ position:'absolute', top:0, left:'15%', right:'15%', height:1,
        background:'linear-gradient(90deg,transparent,rgba(200,200,220,0.35) 40%,rgba(255,255,255,0.55) 50%,rgba(200,200,220,0.35) 60%,transparent)' }} />
      {/* Буквы SWAIP — металлический хром */}
      <span style={{
        position:'relative', zIndex:2,
        fontSize:10, letterSpacing:7, fontWeight:900,
        fontFamily:'"Montserrat","Arial Black",sans-serif',
        textTransform:'uppercase',
        background:'linear-gradient(180deg,#e8e8f0 0%,#ffffff 35%,#b0b0c0 60%,#d8d8e8 80%,#9090a8 100%)',
        WebkitBackgroundClip:'text',
        WebkitTextFillColor:'transparent',
        filter:'drop-shadow(0 0 4px rgba(200,200,255,0.35))',
        paddingLeft:7 /* компенсация letterSpacing у последней буквы */
      } as React.CSSProperties}>SWAIP</span>
      {/* Тонкая горящая линия снизу */}
      <div style={{ position:'absolute', bottom:0, left:'15%', right:'15%', height:1,
        background:'linear-gradient(90deg,transparent,rgba(150,150,180,0.2) 40%,rgba(200,200,220,0.35) 50%,rgba(150,150,180,0.2) 60%,transparent)' }} />
    </div>
  );
}

/* ── Умный текстовый просмотрщик ── */
function TextFileViewer({ url, name }: { url:string; name:string }) {
  const ext = (name.split('.').pop() ?? '').toLowerCase();
  const { t } = useLang();
  const [content, setContent] = React.useState<string|null>(null);
  const [loading, setLoading] = React.useState(true);
  const [error,   setError]   = React.useState(false);
  React.useEffect(() => {
    setLoading(true); setError(false);
    fetch(url, { cache: 'no-store' })
      .then(r => { if (!r.ok) throw new Error(); return r.text(); })
      .then(txt => { setContent(txt); setLoading(false); })
      .catch(() => { setError(true); setLoading(false); });
  }, [url]);

  if (loading) return (
    <div style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', color:'rgba(255,255,255,0.4)' }}>
      <span style={{ fontSize:24, marginRight:10 }}>⏳</span> {t.uploading}
    </div>
  );
  if (error || content === null) return (
    <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center',
      padding:24, gap:12, color:'rgba(255,255,255,0.4)' }}>
      <span style={{ fontSize:40 }}>⚠️</span>
      <span style={{ fontSize:14 }}>{t.cant_load_file}</span>
    </div>
  );

  /* JSON — pretty print */
  if (ext === 'json') {
    let pretty = content;
    try { pretty = JSON.stringify(JSON.parse(content), null, 2); } catch {}
    return (
      <pre style={{ flex:1, padding:16, color:'#7dd3fc', fontSize:12,
        fontFamily:'"Courier New",monospace', whiteSpace:'pre-wrap', wordBreak:'break-word',
        lineHeight:1.7, overflowY:'auto', margin:0, background:'rgba(0,0,0,0.3)' }}>
        {pretty}
      </pre>
    );
  }

  /* CSV — таблица */
  if (ext === 'csv') {
    const rows = content.trim().split('\n').map(r => r.split(',').map(c => c.replace(/^"|"$/g,'')));
    const header = rows[0] ?? [];
    const body   = rows.slice(1);
    return (
      <div style={{ flex:1, overflowY:'auto', overflowX:'auto', padding:12 }}>
        <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
          <thead>
            <tr>
              {header.map((h,i) => (
                <th key={i} style={{ padding:'8px 10px', background:'rgba(59,130,246,0.15)',
                  color:'#93c5fd', textAlign:'left', borderBottom:'1px solid rgba(255,255,255,0.1)',
                  fontFamily:'"Montserrat",sans-serif', fontWeight:700, whiteSpace:'nowrap' }}>
                  {h}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {body.map((row, ri) => (
              <tr key={ri} style={{ background: ri%2===0 ? 'transparent' : 'rgba(255,255,255,0.03)' }}>
                {row.map((cell, ci) => (
                  <td key={ci} style={{ padding:'7px 10px', color:'rgba(255,255,255,0.8)',
                    borderBottom:'1px solid rgba(255,255,255,0.06)', verticalAlign:'top' }}>
                    {cell}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  }

  /* Markdown — базовый рендер */
  if (ext === 'md' || ext === 'markdown') {
    const html = content
      .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
      .replace(/^#{3}\s(.+)$/gm,'<h3 style="color:#93c5fd;margin:16px 0 6px">$1</h3>')
      .replace(/^#{2}\s(.+)$/gm,'<h2 style="color:#60a5fa;margin:20px 0 8px">$1</h2>')
      .replace(/^#{1}\s(.+)$/gm,'<h1 style="color:#3b82f6;margin:24px 0 10px">$1</h1>')
      .replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>')
      .replace(/\*(.+?)\*/g,'<em>$1</em>')
      .replace(/`(.+?)`/g,'<code style="background:rgba(255,255,255,0.1);padding:1px 6px;border-radius:4px;font-family:monospace">$1</code>')
      .replace(/^[-*]\s(.+)$/gm,'<li style="margin:4px 0">$1</li>')
      .replace(/\n/g,'<br>');
    return (
      <div style={{ flex:1, overflowY:'auto', padding:'16px 20px',
        color:'rgba(255,255,255,0.85)', fontSize:14, lineHeight:1.8 }}
        dangerouslySetInnerHTML={{ __html: html }} />
    );
  }

  /* HTML — sandboxed iframe */
  if (ext === 'html' || ext === 'htm') {
    const blob = new Blob([content], { type:'text/html' });
    const blobUrl = URL.createObjectURL(blob);
    return (
      <iframe src={blobUrl} sandbox="allow-scripts"
        style={{ flex:1, width:'100%', minHeight:'100%', border:'none', background:'#fff' }} />
    );
  }

  /* XML — подсветка тегов */
  if (ext === 'xml' || ext === 'svg') {
    const highlighted = content
      .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
      .replace(/(&lt;\/?[\w:.-]+)/g,'<span style="color:#f87171">$1</span>')
      .replace(/([\w:.-]+=)(&quot;[^&]*&quot;)/g,'<span style="color:#fcd34d">$1</span><span style="color:#86efac">$2</span>');
    return (
      <pre style={{ flex:1, padding:16, fontSize:12, fontFamily:'"Courier New",monospace',
        whiteSpace:'pre-wrap', wordBreak:'break-word', lineHeight:1.7, overflowY:'auto', margin:0,
        color:'rgba(255,255,255,0.8)', background:'rgba(0,0,0,0.3)' }}
        dangerouslySetInnerHTML={{ __html: highlighted }} />
    );
  }

  /* RTF — покажем сырой текст (без тегов) */
  if (ext === 'rtf') {
    const plain = content.replace(/\{[^}]*\}/g,'').replace(/\\[a-z]+[-\d]* ?/g,'').replace(/[{}\\]/g,'').trim();
    return (
      <div style={{ flex:1, overflowY:'auto', padding:'16px 20px',
        color:'rgba(255,255,255,0.85)', fontSize:14, lineHeight:1.8, whiteSpace:'pre-wrap' }}>
        {plain || content}
      </div>
    );
  }

  /* TXT / LOG / прочие — обычный текст */
  return (
    <pre style={{ flex:1, padding:16, color:'rgba(255,255,255,0.85)', fontSize:13,
      fontFamily:'"Courier New",monospace', whiteSpace:'pre-wrap', wordBreak:'break-word',
      lineHeight:1.6, overflowY:'auto', margin:0 }}>
      {content}
    </pre>
  );
}

/* ── ZIP-просмотрщик: JSZip через CDN ── */
function ZipFileViewer({ url, name }: { url:string; name:string }) {
  type ZipEntry = { path: string; size: number; isDir: boolean; text?: string };
  const [status,   setStatus]   = React.useState<'loading'|'ok'|'error'>('loading');
  const [entries,  setEntries]  = React.useState<ZipEntry[]>([]);
  const [preview,  setPreview]  = React.useState<{path:string; text:string}|null>(null);

  React.useEffect(() => {
    let cancelled = false;
    setStatus('loading'); setEntries([]); setPreview(null);
    (async () => {
      try {
        /* Загружаем JSZip с CDN */
        if (!(window as any).JSZip) {
          await new Promise<void>((res, rej) => {
            const s = document.createElement('script');
            s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';
            s.onload = () => res(); s.onerror = rej;
            document.head.appendChild(s);
          });
        }
        const JSZip = (window as any).JSZip;
        const buf = await fetch(url, { cache:'no-store' }).then(r => { if(!r.ok) throw new Error(`${r.status}`); return r.arrayBuffer(); });
        if (cancelled) return;
        const zip = await JSZip.loadAsync(buf);
        if (cancelled) return;
        const list: ZipEntry[] = [];
        zip.forEach((relativePath: string, file: any) => {
          list.push({ path: relativePath, size: file._data?.uncompressedSize ?? 0, isDir: file.dir });
        });
        list.sort((a, b) => (a.isDir === b.isDir ? a.path.localeCompare(b.path) : a.isDir ? -1 : 1));
        if (!cancelled) { setEntries(list); setStatus('ok'); }
      } catch { if (!cancelled) setStatus('error'); }
    })();
    return () => { cancelled = true; };
  }, [url]);

  const TEXT_EXTS = ['txt','md','json','xml','csv','html','htm','js','ts','css','log','yaml','yml','ini','cfg','py','sh'];
  const canPreview = (path: string) => TEXT_EXTS.includes((path.split('.').pop()??'').toLowerCase());
  const loadPreview = async (path: string) => {
    try {
      const JSZip = (window as any).JSZip;
      const buf = await fetch(url, { cache:'no-store' }).then(r => r.arrayBuffer());
      const zip = await JSZip.loadAsync(buf);
      const text = await zip.file(path)?.async('string');
      if (text !== undefined) setPreview({ path, text: text.slice(0, 50000) });
    } catch {}
  };

  if (status === 'loading') return (
    <div style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:12 }}>
      <motion.div animate={{ rotate:360 }} transition={{ repeat:Infinity, duration:1, ease:'linear' }}
        style={{ width:40, height:40, borderRadius:'50%', border:'3px solid rgba(167,139,250,0.2)', borderTop:'3px solid #a78bfa' }} />
      <span style={{ fontSize:13, color:'rgba(255,255,255,0.5)' }}>Читаем архив…</span>
    </div>
  );
  if (status === 'error') return (
    <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', gap:16, padding:32 }}>
      <span style={{ fontSize:48 }}>🗜</span>
      <span style={{ fontSize:14, color:'rgba(255,255,255,0.5)', textAlign:'center' }}>Не удалось открыть архив</span>
      <motion.button whileTap={{ scale:0.95 }} onClick={() => { const a=document.createElement('a'); a.href=url; a.download=name; a.click(); }}
        style={{ padding:'10px 20px', borderRadius:12, border:'none', background:'rgba(255,255,255,0.1)', color:'#fff', cursor:'pointer', fontSize:14 }}>
        Скачать
      </motion.button>
    </div>
  );
  if (preview) return (
    <div style={{ flex:1, display:'flex', flexDirection:'column', overflow:'hidden' }}>
      <div style={{ padding:'8px 12px', borderBottom:'1px solid rgba(255,255,255,0.08)',
        display:'flex', alignItems:'center', gap:8 }}>
        <motion.button whileTap={{ scale:0.9 }} onClick={() => setPreview(null)}
          style={{ background:'none', border:'none', color:'rgba(255,255,255,0.5)', cursor:'pointer', fontSize:18, padding:0, lineHeight:1 }}>←</motion.button>
        <span style={{ fontSize:12, color:'rgba(255,255,255,0.6)', flex:1, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{preview.path}</span>
      </div>
      <pre style={{ flex:1, padding:16, color:'rgba(255,255,255,0.85)', fontSize:12,
        fontFamily:'"Courier New",monospace', whiteSpace:'pre-wrap', wordBreak:'break-word',
        lineHeight:1.5, overflowY:'auto', margin:0 }}>{preview.text}</pre>
    </div>
  );
  return (
    <div style={{ flex:1, overflowY:'auto', WebkitOverflowScrolling:'touch' as any }}>
      <div style={{ padding:'10px 12px 4px', fontSize:11, color:'rgba(255,255,255,0.35)', letterSpacing:1, textTransform:'uppercase' }}>
        {entries.length} объект{entries.length===1?'':'ов'} в архиве
      </div>
      {entries.map(e => (
        <div key={e.path}
          onClick={() => !e.isDir && canPreview(e.path) ? loadPreview(e.path) : null}
          style={{ display:'flex', alignItems:'center', gap:10, padding:'10px 12px',
            borderBottom:'1px solid rgba(255,255,255,0.05)',
            cursor: !e.isDir && canPreview(e.path) ? 'pointer' : 'default',
            background: !e.isDir && canPreview(e.path) ? 'transparent' : undefined }}>
          <span style={{ fontSize:18, flexShrink:0 }}>{e.isDir ? '📁' : canPreview(e.path) ? '📃' : '📎'}</span>
          <div style={{ flex:1, minWidth:0 }}>
            <div style={{ fontSize:13, color:'#fff', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', fontWeight: e.isDir?600:400 }}>{e.path}</div>
            {!e.isDir && <div style={{ fontSize:11, color:'rgba(255,255,255,0.35)', marginTop:1 }}>{e.size > 0 ? `${(e.size/1024).toFixed(1)} КБ` : ''}</div>}
          </div>
          {!e.isDir && canPreview(e.path) && <span style={{ fontSize:11, color:'rgba(167,139,250,0.7)' }}>просмотр</span>}
        </div>
      ))}
    </div>
  );
}

/* ── PDF-просмотрщик: встроенный рендер через pdf.js (canvas, без внешнего браузера) ── */
function PdfFileViewer({ url }: { url:string }) {
  const [status,    setStatus]    = React.useState<'loading'|'rendering'|'ok'|'error'>('loading');
  const { t } = useLang();
  const [numPages,  setNumPages]  = React.useState(0);
  const [rendered,  setRendered]  = React.useState(0);
  const containerRef = React.useRef<HTMLDivElement>(null);

  React.useEffect(() => {
    let cancelled = false;
    setStatus('loading');
    setNumPages(0);
    setRendered(0);
    if (containerRef.current) containerRef.current.innerHTML = '';

    (async () => {
      try {
        const buf = await fetch(url, { cache: 'no-store' })
          .then(r => { if (!r.ok) throw new Error(`${r.status}`); return r.arrayBuffer(); });
        if (cancelled) return;

        const pdfjs = await import('pdfjs-dist');
        pdfjs.GlobalWorkerOptions.workerSrc = import.meta.env.BASE_URL + 'pdf.worker.min.mjs';

        const pdf = await pdfjs.getDocument({ data: buf }).promise;
        if (cancelled) return;

        setNumPages(pdf.numPages);
        setStatus('rendering');

        const container = containerRef.current;
        if (!container) return;

        const viewportWidth = container.clientWidth || window.innerWidth;

        for (let i = 1; i <= pdf.numPages; i++) {
          if (cancelled) return;
          const page = await pdf.getPage(i);
          const scale = (viewportWidth * window.devicePixelRatio) / page.getViewport({ scale: 1 }).width;
          const vp = page.getViewport({ scale });

          const canvas = document.createElement('canvas');
          canvas.width  = vp.width;
          canvas.height = vp.height;
          canvas.style.width  = '100%';
          canvas.style.height = 'auto';
          canvas.style.display = 'block';
          canvas.style.marginBottom = '4px';
          canvas.style.background = '#fff';

          const ctx = canvas.getContext('2d')!;
          await page.render({ canvasContext: ctx, viewport: vp, canvas }).promise;
          if (cancelled) return;

          container.appendChild(canvas);
          setRendered(i);
        }
        if (!cancelled) setStatus('ok');
      } catch (e) {
        if (!cancelled) setStatus('error');
      }
    })();

    return () => { cancelled = true; };
  }, [url]);

  const showSpinner = status === 'loading' || status === 'rendering';

  return (
    <div style={{ flex:1, display:'flex', flexDirection:'column', overflow:'hidden', position:'relative' }}>
      {showSpinner && (
        <div style={{ position:'absolute', top:0, left:0, right:0, zIndex:10,
          display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center',
          padding:'20px 0', gap:10, background: status==='loading' ? 'rgba(17,17,17,0.95)' : 'transparent',
          height: status==='loading' ? '100%' : 'auto', pointerEvents:'none' }}>
          <motion.div animate={{ rotate: 360 }} transition={{ repeat:Infinity, duration:1, ease:'linear' }}
            style={{ width:40, height:40, borderRadius:'50%', border:'3px solid rgba(167,139,250,0.2)',
              borderTop:'3px solid #a78bfa' }} />
          <span style={{ fontSize:13, color:'rgba(255,255,255,0.6)' }}>
            {status === 'loading' ? t.loading_doc : `${t.render_label} ${rendered} / ${numPages}`}
          </span>
        </div>
      )}
      {status === 'error' && (
        <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center',
          justifyContent:'center', padding:32, gap:16, color:'rgba(255,255,255,0.5)' }}>
          <span style={{ fontSize:48 }}>📄</span>
          <span style={{ fontSize:14, textAlign:'center' }}>{t.cant_open_pdf}</span>
        </div>
      )}
      <div ref={containerRef}
        style={{ flex:1, overflowY:'auto', padding:'0 2px', WebkitOverflowScrolling:'touch' }} />
    </div>
  );
}

/* ── Office-документ: mammoth.js для Word, SheetJS для Excel ── */
function OfficeFileViewer({ url, name }: { url:string; name:string }) {
  const ext = (name.split('.').pop() ?? '').toLowerCase();
  const { t } = useLang();
  const [fallback, setFallback] = React.useState(false);
  const [status, setStatus]     = React.useState<'loading'|'ok'|'error'>('loading');
  const [html,   setHtml]       = React.useState('');
  const [tableData, setTable]   = React.useState<any[][]>([]);

  

  React.useEffect(() => {
    setStatus('loading'); setHtml(''); setTable([]);

    const loadScript = (src: string, check: string) => new Promise<void>((res, rej) => {
      if ((window as any)[check]) { res(); return; }
      const s = document.createElement('script');
      s.src = src; s.onload = () => res(); s.onerror = rej;
      document.head.appendChild(s);
    });

    fetch(url, { cache: 'no-store' })
      .then(r => { if (!r.ok) throw new Error('fetch'); return r.arrayBuffer(); })
      .then(async buf => {
        if (['doc','docx'].includes(ext)) {
          await loadScript(
            'https://cdnjs.cloudflare.com/ajax/libs/mammoth/1.6.0/mammoth.browser.min.js',
            'mammoth'
          );
          const result = await (window as any).mammoth.convertToHtml({ arrayBuffer: buf });
          setHtml(result.value || '<p>—</p>');
          setStatus('ok');
        } else if (['xls','xlsx'].includes(ext)) {
          await loadScript(
            'https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js',
            'XLSX'
          );
          const XLSX = (window as any).XLSX;
          const wb = XLSX.read(buf, { type:'array' });
          const ws = wb.Sheets[wb.SheetNames[0]];
          const data: any[][] = XLSX.utils.sheet_to_json(ws, { header:1, defval:'' });
          setTable(data);
          setStatus('ok');
        } else {
          setStatus('error');
        }
      })
      .catch(() => setStatus('error'));
  }, [url]);


  if (status === 'loading') return (
    <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center',
      justifyContent:'center', gap:12, color:'rgba(255,255,255,0.5)' }}>
      <span style={{ fontSize:40 }}>⏳</span>
      <span style={{ fontSize:14 }}>{t.loading_doc}</span>
    </div>
  );

  if (status === 'error') return (
    <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center',
      justifyContent:'center', padding:32, gap:16, color:'rgba(255,255,255,0.5)' }}>
      <span style={{ fontSize:48 }}>📄</span>
      <span style={{ fontSize:14, textAlign:'center' }}>{t.cant_open_doc}</span>
      <motion.button whileTap={{ scale:0.95 }}
        onClick={() => blobDownload(url, name)}
        style={{ padding:'12px 28px', borderRadius:50, border:'none', cursor:'pointer',
          background:'rgba(59,130,246,0.2)', color:'#60a5fa', fontWeight:700, fontSize:14,
          fontFamily:'"Montserrat",sans-serif' }}>
        {'⬇ '+t.download_file}
      </motion.button>
    </div>
  );

  /* ── Word → HTML ── */
  if (['doc','docx'].includes(ext)) return (
    <div style={{ flex:1, overflowY:'auto', background:'#fff', padding:'24px 32px',
      color:'#111', fontSize:14, lineHeight:1.8 }}
      dangerouslySetInnerHTML={{ __html: html }} />
  );

  /* ── Excel → таблица ── */
  return (
    <div style={{ flex:1, overflowY:'auto', overflowX:'auto', padding:12 }}>
      <table style={{ borderCollapse:'collapse', fontSize:12, minWidth:'100%' }}>
        <tbody>
          {tableData.map((row, ri) => (
            <tr key={ri} style={{ background: ri===0 ? 'rgba(59,130,246,0.12)' : ri%2===0 ? 'transparent' : 'rgba(255,255,255,0.03)' }}>
              {row.map((cell, ci) =>
                ri === 0
                  ? <th key={ci} style={{ padding:'8px 10px', color:'#93c5fd', textAlign:'left',
                      fontWeight:700, whiteSpace:'nowrap', border:'1px solid rgba(255,255,255,0.1)' }}>
                      {String(cell)}
                    </th>
                  : <td key={ci} style={{ padding:'7px 10px', color:'rgba(255,255,255,0.85)',
                      border:'1px solid rgba(255,255,255,0.06)', verticalAlign:'top' }}>
                      {String(cell)}
                    </td>
              )}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/* ── Скачивание файла через blob (работает с авторизацией, без нового таба) ── */
async function blobDownload(url: string, name: string) {
  try {
    const buf = await fetch(url, { cache: 'no-store' }).then(r => {
      if (!r.ok) throw new Error(`${r.status}`);
      return r.arrayBuffer();
    });
    const blob = new Blob([buf]);
    const burl = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = burl; a.download = name;
    document.body.appendChild(a); a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(burl), 5000);
  } catch { /* ignore */ }
}

/* ── Определение типа файла по имени/MIME ── */
function getFileInfo(name: string, mime = '') {
  const ext = (name.split('.').pop() ?? '').toLowerCase();
  if (mime.startsWith('image/') || ['jpg','jpeg','png','gif','webp','svg','bmp','avif','heic'].includes(ext))
    return { icon:'🖼', label:'Image', viewerType:'image' as const };
  if (mime === 'application/pdf' || ext === 'pdf')
    return { icon:'📄', label:'PDF', viewerType:'pdf' as const };
  if (mime.startsWith('audio/') || ['mp3','wav','ogg','m4a','aac','flac','opus','webm','wma'].includes(ext))
    return { icon:'🎵', label:'Audio', viewerType:'audio' as const };
  if (['doc','docx'].includes(ext) || mime.includes('word'))
    return { icon:'📝', label:'Word', viewerType:'office' as const };
  if (['xls','xlsx'].includes(ext) || mime.includes('excel') || mime.includes('spreadsheet'))
    return { icon:'📊', label:'Excel', viewerType:'office' as const };
  if (['ppt','pptx'].includes(ext) || mime.includes('presentation'))
    return { icon:'📽', label:'PowerPoint', viewerType:'office' as const };
  if (['txt','md','markdown','csv','json','xml','html','htm','log','yaml','yml','ini','cfg','conf','py','js','ts','css','sh','bash'].includes(ext))
    return { icon: ext==='json'?'{}' : ext==='csv'?'📊' : ext==='md'||ext==='markdown'?'📋' : '📃',
      label: ext==='json'?'JSON' : ext==='csv'?'CSV' : ext==='md'||ext==='markdown'?'Markdown' :
             ext==='html'||ext==='htm'?'HTML' : ext==='xml'?'XML' : ext==='rtf'?'RTF' : 'Text',
      viewerType:'text' as const };
  if (['zip','rar','7z','tar','gz'].includes(ext))
    return { icon:'🗜', label:'Archive', viewerType: ext === 'zip' ? 'zip' as const : 'none' as const };
  if (['mp4','mov','avi','mkv','webm'].includes(ext) || mime.startsWith('video/'))
    return { icon:'🎬', label:'Video', viewerType:'video' as const };
  return { icon:'📎', label:'File', viewerType:'none' as const };
}

/* ════════════════════════════════════════════════════════
   ReportModal — модальное окно жалобы на контент
════════════════════════════════════════════════════════ */
const REPORT_CATEGORIES = [
  { key: 'porn',        labelRu: 'Порнография / сексуальный контент', emoji: '🔞' },
  { key: 'csam',        labelRu: 'Контент, связанный с детьми',       emoji: '🚸' },
  { key: 'drugs',       labelRu: 'Наркотики / психоактивные вещества',emoji: '💊' },
  { key: 'violence',    labelRu: 'Насилие / жестокость',              emoji: '⚔️' },
  { key: 'extremism',   labelRu: 'Экстремизм / ненависть',            emoji: '🏴' },
  { key: 'fraud',       labelRu: 'Мошенничество / фишинг',            emoji: '🎣' },
  { key: 'harassment',  labelRu: 'Оскорбления / травля',              emoji: '😡' },
  { key: 'other',       labelRu: 'Другое',                            emoji: '❓' },
] as const;

async function sendReport(payload: {
  contentType: string;
  contentId: string;
  contentText?: string;
  category?: string;
  reason?: string;
}): Promise<void> {
  try {
    await fetch(`${window.location.origin}/api/moderation/report`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify(payload),
    });
  } catch { /* нет интернета — молча игнорируем */ }
}

function ReportModal({ contentType, contentId, contentText, onClose }: {
  contentType: string;
  contentId:   string;
  contentText?: string;
  onClose: () => void;
}) {
  const [selected, setSelected] = React.useState<string>('');
  const [reason,   setReason]   = React.useState('');
  const [sent,     setSent]     = React.useState(false);
  const [sending,  setSending]  = React.useState(false);

  const handleSend = async () => {
    if (!selected) return;
    setSending(true);
    await sendReport({ contentType, contentId, contentText, category: selected, reason: reason.trim() || undefined });
    setSent(true);
    setSending(false);
    setTimeout(onClose, 1800);
  };

  return (
    <div style={{ position:'fixed', inset:0, zIndex:9999, display:'flex', alignItems:'center', justifyContent:'center',
      background:'rgba(0,0,0,0.72)', backdropFilter:'blur(6px)' }} onClick={onClose}>
      <div style={{ background:'#1a1a2e', borderRadius:20, padding:'24px 20px', width:'min(95vw,380px)',
        boxShadow:'0 8px 40px rgba(0,0,0,0.6)', border:'1px solid rgba(255,255,255,0.09)' }}
        onClick={e => e.stopPropagation()}>
        {sent ? (
          <div style={{ textAlign:'center', padding:'16px 0' }}>
            <div style={{ fontSize:40, marginBottom:10 }}>✅</div>
            <p style={{ color:'#fff', margin:0, fontWeight:600 }}>Жалоба отправлена</p>
            <p style={{ color:'rgba(255,255,255,0.5)', fontSize:13, marginTop:6 }}>Наша команда рассмотрит её в ближайшее время.</p>
          </div>
        ) : (
          <>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:16 }}>
              <h3 style={{ color:'#fff', margin:0, fontSize:17, fontWeight:700 }}>🚩 Пожаловаться</h3>
              <button onClick={onClose} style={{ background:'none', border:'none', color:'rgba(255,255,255,0.5)', fontSize:20, cursor:'pointer', padding:0 }}>×</button>
            </div>
            <p style={{ color:'rgba(255,255,255,0.55)', fontSize:13, marginBottom:14, margin:'0 0 14px' }}>Выберите причину жалобы:</p>
            <div style={{ display:'flex', flexDirection:'column', gap:6, marginBottom:14 }}>
              {REPORT_CATEGORIES.map(cat => (
                <button key={cat.key} onClick={() => setSelected(cat.key)}
                  style={{ background: selected === cat.key ? 'rgba(255,100,100,0.18)' : 'rgba(255,255,255,0.04)',
                    border: selected === cat.key ? '1px solid rgba(255,100,100,0.5)' : '1px solid rgba(255,255,255,0.08)',
                    borderRadius:10, padding:'8px 12px', color:'rgba(255,255,255,0.85)', fontSize:13,
                    textAlign:'left', cursor:'pointer', transition:'all 0.15s', display:'flex', alignItems:'center', gap:8 }}>
                  <span>{cat.emoji}</span><span>{cat.labelRu}</span>
                </button>
              ))}
            </div>
            {selected && (
              <textarea placeholder="Дополнительные детали (необязательно)" value={reason} onChange={e => setReason(e.target.value)}
                maxLength={500} rows={3}
                style={{ width:'100%', boxSizing:'border-box', background:'rgba(255,255,255,0.05)',
                  border:'1px solid rgba(255,255,255,0.1)', borderRadius:10, color:'#fff',
                  fontSize:13, padding:'8px 10px', resize:'none', outline:'none', fontFamily:'inherit', marginBottom:12 }} />
            )}
            <button onClick={handleSend} disabled={!selected || sending}
              style={{ width:'100%', padding:'12px 0', borderRadius:12, border:'none',
                background: selected ? 'linear-gradient(135deg,#e53935,#b71c1c)' : 'rgba(255,255,255,0.07)',
                color: selected ? '#fff' : 'rgba(255,255,255,0.3)', fontWeight:700, fontSize:15,
                cursor: selected ? 'pointer' : 'not-allowed', transition:'all 0.2s' }}>
              {sending ? 'Отправка…' : 'Отправить жалобу'}
            </button>
          </>
        )}
      </div>
    </div>
  );
}

/* Хелпер — показывает уведомление о блокировке сервером (статус 451) */
function handleServerContentBlock(resp: Response, t: T): boolean {
  if (resp.status === 451) {
    alert(t.content_blocked);
    return true;
  }
  return false;
}

function FileViewerModal({ file, onClose }: {
  file: { name:string; url:string; mime:string } | null;
  onClose: () => void;
}) {
  const [showViewer, setShowViewer] = React.useState(false);
  const { t } = useLang();
  React.useEffect(() => { if (!file) setShowViewer(false); }, [file]);

  if (!file) return null;
  const fi = getFileInfo(file.name, file.mime);

  return (
    <>
      <AnimatePresence>
        {!showViewer && (
          <>
            <motion.div initial={{ opacity:0 }} animate={{ opacity:1 }} exit={{ opacity:0 }}
              onClick={onClose}
              style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.75)',
                backdropFilter:'blur(6px)', zIndex:1200 }} />
            <motion.div initial={{ y:'100%' }} animate={{ y:0 }} exit={{ y:'100%' }}
              transition={{ type:'spring', stiffness:340, damping:36 }}
              style={{ position:'fixed', bottom:0, left:0, right:0, zIndex:1201,
                background:'#13131a', borderRadius:'22px 22px 0 0',
                border:'1px solid rgba(255,255,255,0.1)',
                padding:'20px 16px 48px' }}>
              <div style={{ width:40, height:4, borderRadius:99,
                background:'rgba(255,255,255,0.18)', margin:'0 auto 18px' }} />
              <div style={{ display:'flex', alignItems:'center', gap:12, marginBottom:22 }}>
                <span style={{ fontSize:36 }}>{fi.icon}</span>
                <div>
                  <div style={{ fontSize:15, fontWeight:700, color:'#fff',
                    fontFamily:'"Montserrat",sans-serif', marginBottom:2 }}>{file.name}</div>
                  <div style={{ fontSize:12, color:'rgba(255,255,255,0.4)' }}>{fi.label}</div>
                </div>
              </div>
              <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
                {fi.viewerType !== 'none' && (
                  <motion.button whileTap={{ scale:0.97 }} onClick={() => setShowViewer(true)}
                    style={{ padding:'14px 0', borderRadius:14, border:'none', cursor:'pointer',
                      background:'rgba(255,255,255,0.1)', color:'#fff', fontSize:15,
                      fontWeight:700, fontFamily:'"Montserrat",sans-serif' }}>
                    {t.open_in_swaip}
                  </motion.button>
                )}
                <motion.button whileTap={{ scale:0.97 }}
                  onClick={() => window.open(file.url, '_blank')}
                  style={{ padding:'14px 0', borderRadius:14, border:'none', cursor:'pointer',
                    background:'rgba(255,255,255,0.06)', color:'rgba(255,255,255,0.75)',
                    fontSize:15, fontWeight:600, fontFamily:'"Montserrat",sans-serif' }}>
                  {t.open_external}
                </motion.button>
                <motion.button whileTap={{ scale:0.97 }}
                  onClick={() => { const a=document.createElement('a'); a.href=file.url; a.download=file.name; document.body.appendChild(a); a.click(); document.body.removeChild(a); }}
                  style={{ padding:'14px 0', borderRadius:14, border:'none', cursor:'pointer',
                    background:'rgba(255,255,255,0.04)', color:'rgba(255,255,255,0.55)',
                    fontSize:15, fontWeight:600, fontFamily:'"Montserrat",sans-serif' }}>
                  {t.download}
                </motion.button>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
      <AnimatePresence>
        {showViewer && (
          <motion.div key="fvm-viewer" initial={{ opacity:0, y:30 }} animate={{ opacity:1, y:0 }}
            exit={{ opacity:0, y:30 }} transition={{ duration:0.22 }}
            style={{ position:'fixed', inset:0, zIndex:1300, background:'#07070f',
              display:'flex', flexDirection:'column' }}>
            <div style={{ display:'flex', alignItems:'center', gap:12,
              padding:'14px 16px', borderBottom:'1px solid rgba(255,255,255,0.1)',
              background:'rgba(255,255,255,0.03)' }}>
              <motion.button whileTap={{ scale:0.9 }} onClick={() => { setShowViewer(false); onClose(); }}
                style={{ width:36, height:36, borderRadius:'50%', border:'none', cursor:'pointer',
                  background:'rgba(255,255,255,0.08)', color:'#fff', fontSize:18, display:'flex',
                  alignItems:'center', justifyContent:'center' }}>←</motion.button>
              <div style={{ flex:1, minWidth:0 }}>
                <div style={{ fontSize:14, fontWeight:700, color:'#fff',
                  fontFamily:'"Montserrat",sans-serif',
                  overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{file.name}</div>
                <div style={{ fontSize:11, color:'rgba(255,255,255,0.4)' }}>{fi.label}</div>
              </div>
              <motion.button whileTap={{ scale:0.9 }} onClick={() => window.open(file.url, '_blank')}
                style={{ width:36, height:36, borderRadius:'50%', border:'none', cursor:'pointer',
                  background:'rgba(255,255,255,0.08)', color:'#fff', fontSize:15, display:'flex',
                  alignItems:'center', justifyContent:'center' }}>⎋</motion.button>
            </div>
            <div style={{ flex:1, overflow:'auto', display:'flex', flexDirection:'column' }}>
              {fi.viewerType === 'pdf' && <PdfFileViewer url={file.url} />}
              {fi.viewerType === 'image' && (
                <div style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', padding:16 }}>
                  <img src={file.url} alt={file.name} style={{ maxWidth:'100%', maxHeight:'100%', objectFit:'contain', borderRadius:8 }} />
                </div>
              )}
              {fi.viewerType === 'audio' && (
                <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:32, gap:20 }}>
                  <span style={{ fontSize:64 }}>🎵</span>
                  <div style={{ fontSize:15, color:'rgba(255,255,255,0.7)', fontWeight:600, textAlign:'center' }}>{file.name}</div>
                  <audio src={file.url} controls style={{ width:'100%', maxWidth:360, marginTop:8 }} />
                </div>
              )}
              {fi.viewerType === 'video' && (
                <div style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', padding:12, background:'#000' }}>
                  <video src={file.url} controls style={{ maxWidth:'100%', maxHeight:'100%', borderRadius:8 }} />
                </div>
              )}
              {fi.viewerType === 'office' && <OfficeFileViewer url={file.url} name={file.name} />}
              {fi.viewerType === 'text' && <TextFileViewer url={file.url} name={file.name} />}
              {fi.viewerType === 'zip' && <ZipFileViewer url={file.url} name={file.name} />}
              {fi.viewerType === 'none' && (
                <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:32, gap:16 }}>
                  <span style={{ fontSize:64 }}>{fi.icon}</span>
                  <div style={{ fontSize:14, color:'rgba(255,255,255,0.5)', textAlign:'center' }}>{t.cant_view_file}</div>
                  <motion.button whileTap={{ scale:0.95 }} onClick={() => window.open(file.url, '_blank')}
                    style={{ padding:'12px 24px', borderRadius:12, border:'none', cursor:'pointer',
                      background:'rgba(255,255,255,0.1)', color:'#fff', fontSize:14, fontWeight:600 }}>
                    Открыть во внешнем приложении
                  </motion.button>
                </div>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}

