/* ══ WIDGET CARD — стабильный компонент вне ProScreen, чтобы не пересоздаваться при каждом ре-рендере ══ */
const _WC_BG   = 'rgba(255,255,255,0.06)';
const _WC_BDR  = '1px solid rgba(255,255,255,0.11)';
const WidgetCardStable = React.memo(function WidgetCardStable({ previewUrl, icon, label, count, accent, onClick, onPreviewChange, onLabelSave }:{
  previewUrl:string; icon:string; label:string; count?:number; accent:string;
  onClick:()=>void; onPreviewChange?:()=>void; onLabelSave?:(v:string)=>void;
}) {
  const [editing, setEditing] = React.useState(false);
  const [draft, setDraft] = React.useState(label);
  const inputRef = React.useRef<HTMLInputElement>(null);

  const startEdit = (e: React.MouseEvent) => {
    e.stopPropagation();
    setDraft(label);
    setEditing(true);
    setTimeout(() => { inputRef.current?.focus(); inputRef.current?.select(); }, 40);
  };
  const saveEdit = () => {
    setEditing(false);
    const v = draft.trim();
    if (v && v !== label) onLabelSave?.(v);
  };

  return (
    <div style={{ position:'relative', flex:'0 0 100px', height:110, borderRadius:16, overflow:'hidden',
      cursor: editing ? 'default' : 'pointer', background: previewUrl ? 'transparent' : _WC_BG,
      border: _WC_BDR, flexShrink:0 }}
      onClick={editing ? undefined : onClick}>
      {previewUrl
        ? <img src={previewUrl} alt="" style={{ width:'100%', height:'100%', objectFit:'cover' }} />
        : <div style={{ width:'100%', height:'100%', display:'flex', flexDirection:'column',
            alignItems:'center', justifyContent:'center', gap:6 }}>
            <span style={{ fontSize:26 }}>{icon}</span>
          </div>
      }
      <div style={{ position:'absolute', inset:0, background:'linear-gradient(to top, rgba(0,0,0,0.75) 55%, transparent 100%)',
        display:'flex', flexDirection:'column', justifyContent:'flex-end', padding:'8px 8px 10px' }}>
        {editing ? (
          <input ref={inputRef} value={draft}
            onChange={e => setDraft(e.target.value)}
            onBlur={saveEdit}
            onKeyDown={e => { if(e.key==='Enter') saveEdit(); if(e.key==='Escape') setEditing(false); }}
            onClick={e => e.stopPropagation()}
            style={{ background:'rgba(0,0,0,0.65)', border:'1px solid rgba(255,255,255,0.45)', borderRadius:6,
              color:'#fff', fontSize:11, fontWeight:700, padding:'3px 6px', width:'100%', outline:'none',
              fontFamily:'inherit', boxSizing:'border-box' }}
          />
        ) : (
          <div style={{ fontSize:11, fontWeight:800, color:'#fff', letterSpacing:'0.04em', lineHeight:1.2 }}>{label}</div>
        )}
        {count !== undefined && count > 0 && !editing && (
          <div style={{ fontSize:10, color:accent, marginTop:2, fontWeight:600 }}>{count} {count===1?'запись':'записей'}</div>
        )}
      </div>
      {/* Кнопка превью 🖼️ */}
      {onPreviewChange && !editing && (
        <motion.button whileTap={{ scale:0.92 }} onClick={e=>{ e.stopPropagation(); onPreviewChange(); }}
          style={{ position:'absolute', top:6, right:6, width:24, height:24, borderRadius:'50%',
            background:'rgba(0,0,0,0.55)', border:'1px solid rgba(255,255,255,0.2)',
            display:'flex', alignItems:'center', justifyContent:'center', fontSize:10, cursor:'pointer', zIndex:2 }}>
          🖼️
        </motion.button>
      )}
      {/* Кнопка переименования ✏️ */}
      {onLabelSave && !editing && (
        <motion.button whileTap={{ scale:0.92 }} onClick={startEdit}
          style={{ position:'absolute', top:6, right: onPreviewChange ? 34 : 6, width:24, height:24, borderRadius:'50%',
            background:'rgba(0,0,0,0.55)', border:'1px solid rgba(255,255,255,0.2)',
            display:'flex', alignItems:'center', justifyContent:'center', fontSize:10, cursor:'pointer', zIndex:2 }}>
          ✏️
        </motion.button>
      )}
    </div>
  );
});

