  const [hlMediaUploading,   setHlMediaUploading] = useState(false);
  const [greetRecording,     setGreetRecording]   = useState(false);
  const [greetRecSecs,       setGreetRecSecs]     = useState(0);
  const [greetUploading,     setGreetUploading]   = useState(false);
  const [greetPaused,        setGreetPaused]      = useState(false);
  const greetMRRef     = useRef<MediaRecorder|null>(null);
  const greetChunksRef = useRef<Blob[]>([]);
  const greetTimerRef  = useRef<ReturnType<typeof setInterval>|null>(null);

  const pauseGreetRecording = () => {
    const mr = greetMRRef.current;
    if (!mr || mr.state !== 'recording') return;
    mr.pause();
    setGreetPaused(true);
    if (greetTimerRef.current) clearInterval(greetTimerRef.current);
  };
  const resumeGreetRecording = () => {
    const mr = greetMRRef.current;
    if (!mr || mr.state !== 'paused') return;
    mr.resume();
    setGreetPaused(false);
    greetTimerRef.current = setInterval(() => setGreetRecSecs(s => s + 1), 1000);
  };
  const startGreetRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      greetChunksRef.current = [];
      /* Выбираем лучший поддерживаемый MIME-тип для записи */
      const greetMimeTypes = [
        'audio/webm;codecs=opus', 'audio/webm',
        'audio/mp4', 'audio/ogg;codecs=opus', 'audio/ogg',
      ];
      const greetMime = greetMimeTypes.find(t => { try { return MediaRecorder.isTypeSupported(t); } catch { return false; } }) || '';
      const mr = new MediaRecorder(stream, greetMime ? { mimeType: greetMime } : {});
      greetMRRef.current = mr;
      mr.ondataavailable = e => { if (e.data.size > 0) greetChunksRef.current.push(e.data); };
      mr.onstop = async () => {
        stream.getTracks().forEach(t => t.stop());
        if (greetTimerRef.current) clearInterval(greetTimerRef.current);
        setGreetRecording(false);
        setGreetPaused(false);
        const actualMime = mr.mimeType || greetMime || 'audio/webm';
        const blob = new Blob(greetChunksRef.current, { type: actualMime });
        if (blob.size === 0) return;
        setGreetUploading(true);
        try {
          /* /api/greeting-upload → GCS (постоянное хранилище) */
          const res = await fetch(`${window.location.origin}/api/greeting-upload`, {
            method: 'POST',
            headers: { 'Content-Type': actualMime, 'x-session-token': getST() || '' },
            body: blob,
          });
          if (res.ok) {
            const d = await res.json();
            setProGreetingUrl(d.url);
            /* Немедленный синк — чтобы URL появился у гостей сразу */
            setTimeout(() => _swaipSyncNow.fn?.(), 300);
            setTimeout(() => _swaipSyncNow.fn?.(), 1500);
            setTimeout(() => _swaipSyncNow.fn?.(), 4000);
          }
        } catch {}
        finally { setGreetUploading(false); }
      };
      mr.start(200);
      setGreetRecording(true);
      setGreetRecSecs(0);
      greetTimerRef.current = setInterval(() => setGreetRecSecs(s => s + 1), 1000);
    } catch {}
  };
  const stopGreetRecording = () => { greetMRRef.current?.stop(); };
  const uploadGreetingFile = async (file: File) => {
    setGreetUploading(true);
    try {
      /* /api/greeting-upload → GCS (постоянное хранилище, не теряется при передеплое) */
      const res = await fetch(`${window.location.origin}/api/greeting-upload`, {
        method: 'POST',
        headers: { 'Content-Type': file.type || 'audio/mpeg', 'x-filename': file.name, 'x-session-token': getST() || '' },
        body: await file.arrayBuffer(),
      });
      if (res.ok) {
        const d = await res.json();
        setProGreetingUrl(d.url);
        setTimeout(() => _swaipSyncNow.fn?.(), 300);
        setTimeout(() => _swaipSyncNow.fn?.(), 1500);
        setTimeout(() => _swaipSyncNow.fn?.(), 4000);
      }
    } finally { setGreetUploading(false); }
  };
  /* ── Голосовое приветствие (Web Speech API) ── */
  const ttsVoicesRef = useRef<SpeechSynthesisVoice[]>([]);
  useEffect(() => {
    if (!('speechSynthesis' in window)) return;
    const load = () => { ttsVoicesRef.current = window.speechSynthesis.getVoices(); };
    load();
    window.speechSynthesis.onvoiceschanged = load;
    return () => { window.speechSynthesis.onvoiceschanged = null; };
  }, []);
  /* ── CSS-анимация пульса и разрешение уведомлений ── */
  useEffect(() => {
    const id = 'pro-pulse-kf';
    if (!document.getElementById(id)) {
      const s = document.createElement('style');
      s.id = id;
      s.textContent = `
        @keyframes proBookingPulse {
          0%   { box-shadow: 0 0 0 0 rgba(239,68,68,0.8); }
          60%  { box-shadow: 0 0 0 10px rgba(239,68,68,0); }
          100% { box-shadow: 0 0 0 0 rgba(239,68,68,0); }
        }
        .pro-booking-pulse {
          animation: proBookingPulse 1.5s ease-out infinite !important;
          border-color: rgba(239,68,68,0.7) !important;
          background: linear-gradient(135deg,rgba(239,68,68,0.22),rgba(185,28,28,0.12)) !important;
        }
        .pro-booking-pulse span { color: #fca5a5 !important; }
      `;
      document.head.appendChild(s);
    }
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, []);
  /* ── Заявки от гостей (server-side booking_requests) ── */
  type GuestRequest = { id:string; clientName:string; clientPhone:string; service:string; text:string; status:string; createdAt:string; };
  const [guestRequests,    setGuestRequests]    = useState<GuestRequest[]>([]);
  const [seenReqIds,       setSeenReqIds]       = usePersistedState<string[]>('pro_seenReqIds', [], userHash);
  const prevReqCountRef = useRef(-1);
  /* ── Оповещение владельца о новой записи ── */
  const prevTotalRef = useRef(-1);
  useEffect(() => {
    const total = bookings.length + freeBookings.length;
    if (prevTotalRef.current === -1) { prevTotalRef.current = total; return; }
    if (total <= prevTotalRef.current) { prevTotalRef.current = total; return; }
    prevTotalRef.current = total;
    const all = [...bookings, ...freeBookings].sort((a,b) => b.createdAt > a.createdAt ? -1 : 1);
    const latest = all[all.length - 1];
    if (!latest) return;
    const notifTitle = '📅 Новая запись!';
    const slotSpeech = fmtSlotSpeech(latest.slot);
    const d = new Date(latest.slot.replace(' ','T'));
    const dateStr = d.toLocaleDateString('ru-RU', {weekday:'long', day:'numeric', month:'long'}) + ' в ' + latest.slot.split(' ')[1];
    const notifBody  = `${latest.clientName} — ${latest.itemName}\n${dateStr}`;
    const voiceText  = `Внимание! У вас новая запись. ${latest.clientName} записался на ${latest.itemName} ${slotSpeech}.`;
    if ('Notification' in window && Notification.permission === 'granted') {
      if (navigator.serviceWorker?.controller) {
        navigator.serviceWorker.controller.postMessage({ type:'SHOW_BOOKING_NOTIFICATION', title:notifTitle, body:notifBody, tag:'booking-'+latest.id });
      } else {
        new Notification(notifTitle, { body:notifBody, icon:'/swaip-logo.png' });
      }
    }
    speakGreeting(voiceText);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [bookings.length, freeBookings.length]);

  /* ── Поллинг заявок от гостей каждые 10 секунд ── */
  useEffect(() => {
    const token = getST();
    if (!token) return;
    const poll = async () => {
      try {
        const r = await fetch(`${window.location.origin}/api/account/booking-requests`, {
          headers: { 'x-session-token': token }
        });
        if (!r.ok) return;
        const data = await r.json() as { requests: GuestRequest[] };
        const reqs = data.requests || [];
        setGuestRequests(reqs);
        const newReqs = reqs.filter(rq => !seenReqIds.includes(rq.id) && rq.status === 'new');
        if (prevReqCountRef.current === -1) { prevReqCountRef.current = reqs.length; return; }
        if (newReqs.length === 0 || reqs.length <= prevReqCountRef.current) { prevReqCountRef.current = reqs.length; return; }
        prevReqCountRef.current = reqs.length;
        /* Самая новая заявка */
        const latest = newReqs[newReqs.length - 1];
        const voiceText = `Внимание! К вам записался ${latest.clientName}. Услуга: ${latest.service || 'запись'}. Телефон: ${latest.clientPhone}.`;
        /* Трынь-трынь перед голосом */
        await playPhoneRing(3);
        speakGreeting(voiceText);
      } catch {}
    };
    poll();
    const iv = setInterval(poll, 10_000);
    return () => clearInterval(iv);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [seenReqIds.length]);

  /* ── Загрузка баланса монет + клейм реферала ── */
  useEffect(() => {
    const token = getST();
    if (!token || !userHash) return;
    (async () => {
      try {
        const r = await fetch(`${window.location.origin}/api/referral/stats`, {
          headers: { 'x-session-token': token }
        });
        if (r.ok) {
          const d = await r.json();
          setCoinBalance(d.coinBalance ?? 0);
          setReferralCount(d.referralsCount ?? 0);
        }
      } catch {}
    })();
    /* Клейм реферала если есть ?ref= в URL и пользователь только что зашёл */
    const refKey = `swaip_ref_claimed_${userHash}`;
    try {
      const urlRef = new URLSearchParams(window.location.search).get('ref') ||
                     sessionStorage.getItem('swaip_pending_ref');
      if (urlRef && urlRef.length >= 8 && !localStorage.getItem(refKey)) {
        sessionStorage.removeItem('swaip_pending_ref');
        setReferralClaiming(urlRef);
        fetch(`${window.location.origin}/api/referral/claim`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'x-session-token': token },
          body: JSON.stringify({ referrerHashPrefix: urlRef }),
        }).then(async (cr) => {
          if (cr.ok) {
            const cd = await cr.json();
            setCoinBalance(prev => prev + (cd.coinsEarned ?? 0));
            localStorage.setItem(refKey, '1');
          }
        }).catch(() => {}).finally(() => setReferralClaiming(null));
      }
    } catch {}
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [userHash]);

  const getTimeGreeting = () => {
    const h = new Date().getHours();
    if (h >= 5  && h < 12) return 'Доброго утра';
    if (h >= 12 && h < 17) return 'Доброго дня';
    if (h >= 17 && h < 23) return 'Доброго вечера';
    return 'Доброй ночи';
  };
  /* ── Полноценная речевая форма даты и времени ── */
  const fmtSlotSpeech = (slot: string): string => {
    const d = new Date(slot.replace(' ', 'T'));
    const DAY_ACC = ['воскресенье','понедельник','вторник','среду','четверг','пятницу','субботу'];
    const MON_GEN = ['января','февраля','марта','апреля','мая','июня','июля','августа','сентября','октября','ноября','декабря'];
    const DATE_GEN: Record<number,string> = {
      1:'первого',2:'второго',3:'третьего',4:'четвёртого',5:'пятого',
      6:'шестого',7:'седьмого',8:'восьмого',9:'девятого',10:'десятого',
      11:'одиннадцатого',12:'двенадцатого',13:'тринадцатого',14:'четырнадцатого',
      15:'пятнадцатого',16:'шестнадцатого',17:'семнадцатого',18:'восемнадцатого',
      19:'девятнадцатого',20:'двадцатого',21:'двадцать первого',22:'двадцать второго',
      23:'двадцать третьего',24:'двадцать четвёртого',25:'двадцать пятого',
      26:'двадцать шестого',27:'двадцать седьмого',28:'двадцать восьмого',
      29:'двадцать девятого',30:'тридцатого',31:'тридцать первого',
    };
    const HR_ACC = ['двенадцать','час','два','три','четыре','пять','шесть','семь','восемь','девять','десять','одиннадцать',
      'двенадцать','тринадцать','четырнадцать','пятнадцать','шестнадцать','семнадцать','восемнадцать','девятнадцать','двадцать','двадцать один','двадцать два','двадцать три'];
    const HR_SUFFIX = ['часов','час','часа','часа','часа','часов','часов','часов','часов','часов','часов','часов',
      'часов','часов','часов','часов','часов','часов','часов','часов','часов','часа','часа','часа'];
    const MIN_W: Record<number,string> = {
      1:'одну',2:'две',3:'три',4:'четыре',5:'пять',6:'шесть',7:'семь',8:'восемь',9:'девять',10:'десять',
      11:'одиннадцать',12:'двенадцать',13:'тринадцать',14:'четырнадцать',15:'пятнадцать',
      16:'шестнадцать',17:'семнадцать',18:'восемнадцать',19:'девятнадцать',20:'двадцать',
      25:'двадцать пять',30:'тридцать',35:'тридцать пять',40:'сорок',45:'сорок пять',50:'пятьдесят',55:'пятьдесят пять',
    };
    const HALF_GEN = ['двенадцатого','первого','второго','третьего','четвёртого','пятого','шестого',
      'седьмого','восьмого','девятого','десятого','одиннадцатого','двенадцатого',
      'первого','второго','третьего','четвёртого','пятого','шестого','седьмого','восьмого','девятого','десятого','одиннадцатого'];
    const [hStr, mStr] = slot.split(' ')[1].split(':');
    const h = parseInt(hStr); const m = parseInt(mStr);
    let timeStr: string;
    if (m === 0) {
      timeStr = `в ${HR_ACC[h]} ${HR_SUFFIX[h]}`;
      if (h === 1 || h === 13) timeStr = 'в час';
    } else if (m === 30) {
      timeStr = `в половине ${HALF_GEN[(h + 1) % 24]}`;
    } else {
      const minSuffix = m === 1 ? 'минуту' : (m >= 2 && m <= 4) || (m >= 22 && m <= 24) ? 'минуты' : 'минут';
      timeStr = `в ${HR_ACC[h]} ${HR_SUFFIX[h]} ${MIN_W[m] || m} ${minSuffix}`;
    }
    const dayAcc = DAY_ACC[d.getDay()];
    const dateG   = DATE_GEN[d.getDate()] || d.getDate().toString();
    const monthG  = MON_GEN[d.getMonth()];
    return `в ${dayAcc}, ${dateG} ${monthG}, ${timeStr}`;
  };
  const speakGreeting = useCallback((text: string) => {
    if (!('speechSynthesis' in window)) return;
    window.speechSynthesis.cancel();
    const clean = text.replace(/[^\u0020-\u007E\u00A0-\u024F\u0400-\u04FF\s]/g,'').trim();
    const utt = new SpeechSynthesisUtterance(clean);
    utt.lang = 'ru-RU'; utt.rate = 0.92; utt.pitch = 1.05;
    const voices = ttsVoicesRef.current.length > 0 ? ttsVoicesRef.current : window.speechSynthesis.getVoices();
    const ruVoice = voices.find(v => v.lang.startsWith('ru'));
    if (ruVoice) utt.voice = ruVoice;
    window.speechSynthesis.speak(utt);
  }, []);
