        if (lv === 'silk')      return { textAlign:'center' as const, padding:'76px 20px 0', position:'relative' as const, zIndex:2, marginTop:'-14px', background:'rgba(45,0,24,0.98)', borderTop:`1px solid ${ac}30` };
        if (lv === 'neon')      return { textAlign:'right' as const,  padding:'16px 146px 0 16px', position:'relative' as const, zIndex:2, marginTop:'-14px', background:'rgba(11,0,20,1)', borderTop:`2px solid ${ac}` };
