        if (lv === 'glam')      return { textAlign:'center' as const, padding:'82px 24px 0', position:'relative' as const, zIndex:2, marginTop:'-14px', background:'rgba(10,0,8,0.99)', borderTop:`1px solid ${ac}30` };
