        if (lv === 'cosmic')    return { textAlign:'center' as const, padding:'84px 20px 0', position:'relative' as const, zIndex:2, marginTop:'-14px', background:'rgba(0,8,20,1)', borderTop:`1px solid ${ac}25` };
