                  <motion.div key={i} whileTap={{ scale:0.98 }}
                    onClick={() => setShowMetricEdit(proMetrics.indexOf(m))}
                    style={{ display:'flex', alignItems:'center', justifyContent:'space-between',
                      padding:'9px 14px', cursor:'pointer',
                      background: i % 2 === 0 ? `${activeTheme.accent}09` : 'transparent',
                      borderBottom: i < active.length-1 ? `1px solid ${activeTheme.accent}20` : 'none' }}>
                    <span style={{ fontSize:11, color:'rgba(255,255,255,0.6)',
                      fontFamily:'"Montserrat",sans-serif', textTransform:'uppercase', letterSpacing:'0.05em' }}>{m.label}</span>
                    <span style={{ fontSize:19, fontWeight:900, color:activeTheme.accent,
                      fontFamily:'"Bebas Neue",sans-serif', letterSpacing:'0.02em' }}>{m.val}</span>
                  </motion.div>
