                            setChatMessages([{ role:'bot', text:`Здравствуйте! 😊 Меня зовут ${assistantName}, я помогу вам записаться на «${item.name}».\n\nВот свободные слоты:\n${itemFreeSlots.map(fmt).map(s=>'📅 '+s).join('\n')}\n\nВыберите удобное время или напишите мне — я всегда помогу! 👇` }]);
