          {/* Область видео с рамкой — адаптивная под экран */}
          <div style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', overflow:'hidden', padding:'8px 10px' }}>
            {(() => {
              const FRAME_DIMS: Record<string,[number,number]> = {
                retro_tv:[300,420], modern_tv:[300,350], car_mirror:[320,200],
                wall_mirror:[280,440], microwave:[300,360], apt_window:[300,420],
                village_window:[300,460], camcorder:[320,240], dslr:[320,240],
                phone:[280,520], monitor:[300,370], laptop:[360,440],
              };
              const [frameW, frameH] = FRAME_DIMS[selfieFrame] ?? [300,420];
              const maxW = Math.min(window.innerWidth - 16, 420);
              const availH = window.innerHeight - 54 - (selfieBlob ? 0 : 48) - 96;
              const sc = Math.min(1, maxW / frameW, availH / frameH);
              const dispW = Math.round(frameW * sc);
              const dispH = Math.round(frameH * sc);
              return (
                <div ref={selfiePinchContainerRef}
                  style={{ width: dispW, height: dispH, overflow: 'hidden', flexShrink: 0, display:'flex', alignItems:'center', justifyContent:'center', position:'relative' }}>
                  <div style={{ transform: `scale(${sc})`, transformOrigin: 'top center', flexShrink: 0 }}>
                    <SelfieFrameWrapper frameId={selfieFrame}>
                      {selfieBlob
                        ? <video src={selfiePreviewUrl ?? undefined} autoPlay loop playsInline controls style={{ width:'100%', height:'100%', objectFit:'cover' }} />
                        : <video ref={selfieVideoRef} autoPlay playsInline muted style={{ width:'100%', height:'100%', objectFit:'cover',
                            transform: `scale(${selfieZoom}) ${selfieCamera==='user' ? 'scaleX(-1)' : ''}`,
                            transformOrigin:'center', transition:'transform 0.05s' }} />
                      }
                    </SelfieFrameWrapper>
                  </div>
                  {/* Индикатор зума */}
                  {selfieZoom > 1.05 && !selfieBlob && (
                    <div style={{ position:'absolute', top:8, left:'50%', transform:'translateX(-50%)', background:'rgba(0,0,0,0.6)', color:'#fff', borderRadius:12, padding:'3px 10px', fontSize:12, fontWeight:700, pointerEvents:'none' }}>
                      {selfieZoom.toFixed(1)}×
                    </div>
                  )}
                  {/* Подсказка о камере */}
                  {!selfieBlob && (
                    <div style={{ position:'absolute', bottom:8, left:'50%', transform:'translateX(-50%)', background:'rgba(0,0,0,0.5)', color:'rgba(255,255,255,0.7)', borderRadius:10, padding:'2px 8px', fontSize:10, pointerEvents:'none', whiteSpace:'nowrap' }}>
                      {selfieCamera==='user' ? '📷 Фронт. камера' : '📷 Осн. камера'} · Пинч для зума
                    </div>
                  )}
                </div>
              );
            })()}
          </div>

