                    {certEditUploading && <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.6)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:14, color:'#60a5fa' }}>⏳ Загрузка...</div>}
