const EMOJIS_CHAT = ['😀','😂','❤️','🔥','👍','👎','😮','😢','😡','🎉','💯','🙏','✨','💪','👏','🤔','😍','🤣','😎','👋','🌊','⚡','💎','🚀','🎤','🎧','🎶','📸','🤝','💬'];

interface ConvUser { name: string; avatar: string; handle: string; }
interface GroupParticipant { hash: string; info: ConvUser; }
interface ConvItem  { id: number; type: string; otherHash: string; otherInfo: ConvUser; name: string|null; participants: GroupParticipant[]; lastMessage: MsgItem|null; unreadCount: number; lastMessageAt: string; }
interface MsgItem   { id: number; conversationId: number; senderHash: string; content: string; messageType: string; mediaUrl: string|null; mediaName: string|null; duration: number|null; isRead: boolean; createdAt: string; author: ConvUser; }

function Avatar32({ info, accent }: { info: ConvUser; accent: string }) {
  if (info.avatar && !info.avatar.startsWith('blob:')) {
    return <img src={info.avatar} alt="" style={{ width:'100%', height:'100%', objectFit:'cover' }} />;
  }
  const initials = info.name.split(' ').map(w=>w[0]||'').join('').slice(0,2).toUpperCase() || '?';
  return <div style={{ width:'100%', height:'100%', background:`${accent}33`, display:'flex', alignItems:'center', justifyContent:'center', fontSize:16, fontWeight:700, color:accent }}>{initials}</div>;
}

function formatMsgTime(iso: string) {
  const d = new Date(iso);
  const now = new Date();
  const diffMs = now.getTime() - d.getTime();
  if (diffMs < 60000) return 'только что';
  if (diffMs < 3600000) return `${Math.floor(diffMs/60000)} мин`;
  if (d.toDateString() === now.toDateString()) return d.toLocaleTimeString('ru',{hour:'2-digit',minute:'2-digit'});
  return d.toLocaleDateString('ru',{day:'2-digit',month:'short'});
}

function getMsgPreview(m: MsgItem|null): string {
  if (!m) return 'Новый чат';
  if (m.messageType === 'audio')        return '🎤 Голосовое';
  if (m.messageType === 'videoMessage') return '🎬 Видеосообщение';
  if (m.messageType === 'image') return '📸 Фото';
  if (m.messageType === 'video') return '🎬 Видео';
  if (m.messageType === 'gif')   return '🎞 GIF';
  if (m.messageType === 'file')  return `📎 ${m.mediaName || 'Файл'}`;
  return m.content || '…';
}

/* ─── Кнопка «Добавить в друзья» в карточке приглашения ─── */
function SwaipInviteButton({ targetHash, inviteUrl, myHash, accent, onViewProfile }: {
  targetHash: string; inviteUrl: string; myHash: string; accent: string;
  onViewProfile?: (h: string) => void;
}) {
  const [state, setState] = useState<'idle'|'loading'|'done'>('idle');
  const handleAdd = async () => {
    if (!myHash || !getST()) {
      /* Не залогинен — открываем профиль */
      onViewProfile ? onViewProfile(targetHash) : window.open(inviteUrl, '_self');
      return;
    }
    setState('loading');
    try {
      await fetch(`${window.location.origin}/api/follows/mutual`, {
        method: 'POST', headers: { 'Content-Type':'application/json', 'x-session-token': getST() },
        body: JSON.stringify({ targetHash }),
      });
      setState('done');
    } catch { setState('idle'); }
  };
  if (state === 'done') {
    return (
      <div style={{ display:'flex', alignItems:'center', gap:6, padding:'8px 0',
        color:'#4ade80', fontSize:12, fontWeight:800, fontFamily:'"Montserrat",sans-serif' }}>
        ✓ Вы теперь друзья в SWAIP
      </div>
    );
  }
  return (
    <div style={{ display:'flex', gap:6 }}>
      <motion.button whileTap={{ scale:0.95 }} onClick={handleAdd} disabled={state === 'loading'}
        style={{ flex:1, padding:'8px', borderRadius:100, border:'none',
          background: state === 'loading' ? 'rgba(201,152,58,0.5)' : '#c9983a',
          color:'#000', fontWeight:900, fontSize:12,
          fontFamily:'"Montserrat",sans-serif', cursor:'pointer' }}>
        {state === 'loading' ? '…' : '👥 Добавить в друзья'}
      </motion.button>
      <motion.button whileTap={{ scale:0.95 }}
        onClick={() => onViewProfile ? onViewProfile(targetHash) : window.open(inviteUrl, '_self')}
        style={{ padding:'8px 12px', borderRadius:100,
          border:'1px solid rgba(201,152,58,0.4)', background:'transparent',
          color:'#c9983a', fontSize:12, fontWeight:700,
          fontFamily:'"Montserrat",sans-serif', cursor:'pointer' }}>
        →
      </motion.button>
    </div>
  );
}

/* ─── Chat Window ─── */
function ChatScreen({ convId, otherHash, otherInfo, myHash, accent, onBack, isGroup: isGroupProp, groupName: groupNameProp, participants: participantsProp, onViewProfile }:
  { convId: number; otherHash: string; otherInfo: ConvUser; myHash: string; accent: string; onBack: () => void; onViewProfile?: (hash: string) => void;
    isGroup?: boolean; groupName?: string|null; participants?: GroupParticipant[]; }) {
  const { t } = useLang();
  const C = { bg:'#0a0c14', card:'rgba(255,255,255,0.04)', border:'rgba(255,255,255,0.07)', sub:'rgba(255,255,255,0.4)' };

  /* Back button → close chat */
  useBackHandler(onBack);

  const [messages,      setMessages]      = useState<MsgItem[]>([]);
  const [input,         setInput]         = useState('');
  const [sending,       setSending]       = useState(false);
  const [uploadingFile, setUploadingFile] = useState<string|null>(null);
  const [showEmoji,     setShowEmoji]     = useState(false);
  const [recording,     setRecording]     = useState(false);
  const [recSec,        setRecSec]        = useState(0);
  const [videoOpen,     setVideoOpen]     = useState(false);
  const [videoRecording,setVideoRecording]= useState(false);
  const [videoSec,      setVideoSec]      = useState(0);
  const [camFacing,     setCamFacing]     = useState<'user'|'environment'>('user');
  const [videoTick,     setVideoTick]     = useState(0); // force re-render for srcObject
  type VFrame = 'filmstrip'|'retrotv'|'camera'|'camcorder'|'balloon';
  const [videoFrame,    setVideoFrame]    = useState<VFrame>('filmstrip');
  const [isOnline,      setIsOnline]      = useState(false);
  const [isGroup,       setIsGroup]       = useState(isGroupProp ?? false);
  const [groupName,     setGroupName]     = useState(groupNameProp ?? '');
  const [participants,  setParticipants]  = useState<GroupParticipant[]>(participantsProp ?? []);
  const [showAddModal,  setShowAddModal]  = useState(false);
  const [showMembers,   setShowMembers]   = useState(false);
  const [contacts,      setContacts]      = useState<GroupParticipant[]>([]);
  const [adding,        setAdding]        = useState<string|null>(null);
  const [editingName,   setEditingName]   = useState(false);
  const [newGroupName,  setNewGroupName]  = useState('');
  const bottomRef     = useRef<HTMLDivElement>(null);
  const mediaRef      = useRef<MediaRecorder|null>(null);
  const chunksRef     = useRef<Blob[]>([]);
  const timerRef      = useRef<ReturnType<typeof setInterval>|null>(null);
  const inputRef      = useRef<HTMLInputElement>(null);
  const vidPreviewRef = useRef<HTMLVideoElement|null>(null);
  const vidStreamRef  = useRef<MediaStream|null>(null);
  const vidMediaRef   = useRef<MediaRecorder|null>(null);
  const vidChunksRef  = useRef<Blob[]>([]);
  const vidTimerRef   = useRef<ReturnType<typeof setInterval>|null>(null);

  /* ── Звонки — берём из глобального контекста CompassScreen ── */
  const call = useCall();

  const loadMessages = async () => {
    try {
      const r = await fetch(`${API_BASE}/api/conversations/${convId}/messages`, { headers: { 'x-session-token': getST() } });
      if (r.ok) { const { messages: ms } = await r.json(); setMessages(ms ?? []); }
    } catch {}
  };

  useEffect(() => { loadMessages(); const t = setInterval(loadMessages, 4000); return () => clearInterval(t); }, [convId]);
  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior:'smooth' }); }, [messages.length]);

  const loadContacts = async () => {
    try {
      const r = await fetch(`${API_BASE}/api/contacts`, { headers: { 'x-session-token': getST() } });
      if (r.ok) { const { contacts: cs } = await r.json(); setContacts(cs ?? []); }
    } catch {}
  };

  const handleAddParticipant = async (addHash: string) => {
    setAdding(addHash);
    try {
      const r = await fetch(`${API_BASE}/api/conversations/${convId}/participants`, {
        method:'POST', headers:{ 'Content-Type':'application/json', 'x-session-token': getST() },
        body: JSON.stringify({ addHash }),
      });
      if (r.ok) {
        const data = await r.json();
        if (data.conversation) {
          setIsGroup(data.conversation.type === 'group');
          setGroupName(data.conversation.name ?? '');
          setParticipants(data.conversation.participants ?? []);
        }
        await loadMessages();
        setShowAddModal(false);
      }
    } catch {}
    setAdding(null);
  };

  const handleLeaveGroup = async () => {
    if (!confirm(t.leave_chat)) return;
    try {
      await fetch(`${API_BASE}/api/conversations/${convId}/participants`, {
        method:'DELETE', headers:{ 'x-session-token': getST() },
      });
      onBack();
    } catch {}
  };

  const handleRenameGroup = async () => {
    if (!newGroupName.trim()) return;
    try {
      const r = await fetch(`${API_BASE}/api/conversations/${convId}`, {
        method:'PATCH', headers:{ 'Content-Type':'application/json', 'x-session-token': getST() },
        body: JSON.stringify({ name: newGroupName.trim() }),
      });
      if (r.ok) { setGroupName(newGroupName.trim()); setEditingName(false); }
    } catch {}
  };

  const sendMsg = async (content: string, type = 'text', mediaUrl?: string, mediaName?: string, dur?: number) => {
    if (sending) return;
    setSending(true);
    try {
      const body: Record<string,unknown> = { content, messageType: type };
      if (mediaUrl) body.mediaUrl = mediaUrl;
      if (mediaName) body.mediaName = mediaName;
      if (dur) body.duration = dur;
      const r = await fetch(`${API_BASE}/api/conversations/${convId}/messages`, {
        method:'POST', headers:{ 'Content-Type':'application/json', 'x-session-token': getST() },
        body: JSON.stringify(body),
      });
      if (r.ok) { const msg = await r.json(); setMessages(p => [...p, msg]); }
    } catch {}
    setSending(false);
  };

  const handleSend = async () => {
    const txt = input.trim();
    if (!txt) return;
    setInput('');
    await sendMsg(txt, 'text');
  };

  const handleFile = async (file: File) => {
    if (file.size > 80 * 1024 * 1024) {
      alert('Файл слишком большой (максимум 80 МБ). Выберите файл меньшего размера.');
      return;
    }
    const isImg = file.type.startsWith('image/gif') ? 'gif' : file.type.startsWith('image/') ? 'image' : null;
    const isVid = file.type.startsWith('video/') ? 'video' : null;
    const type  = isImg || isVid || 'file';
    const shortName = file.name.length > 24 ? file.name.slice(0, 22) + '…' : file.name;
    setUploadingFile(shortName);
    try {
      const url = await uploadToStorage(file);
      /* sendMsg может быть заблокирован флагом sending — обходим напрямую */
      const body: Record<string,unknown> = { content: '', messageType: type, mediaUrl: url, mediaName: file.name };
      const r = await fetch(`${API_BASE}/api/conversations/${convId}/messages`, {
        method:'POST', headers:{ 'Content-Type':'application/json', 'x-session-token': getST() },
        body: JSON.stringify(body),
      });
      if (r.ok) { const msg = await r.json(); setMessages(p => [...p, msg]); }
    } catch (err) {
      console.error('Ошибка загрузки файла:', err);
      alert(`Не удалось отправить файл "${shortName}". Проверьте соединение и попробуйте ещё раз.`);
    } finally {
      setUploadingFile(null);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mr = new MediaRecorder(stream);
      chunksRef.current = [];
      mr.ondataavailable = e => { if (e.data.size > 0) chunksRef.current.push(e.data); };
      mr.start();
      mediaRef.current = mr;
      setRecording(true);
      setRecSec(0);
      timerRef.current = setInterval(() => setRecSec(s => s + 1), 1000);
    } catch {}
  };

  const stopRecording = async () => {
    if (!mediaRef.current) return;
    const mr = mediaRef.current;
    const dur = recSec;
    mediaRef.current = null;
    if (timerRef.current) { clearInterval(timerRef.current); timerRef.current = null; }
    setRecording(false);
    setRecSec(0);

    /* Ждём onstop ПЕРЕД вызовом stop() — иначе событие может пройти раньше */
    await new Promise<void>(resolve => {
      mr.onstop = () => resolve();
      mr.stop();
      mr.stream.getTracks().forEach(t => t.stop());
    });

    /* Небольшая задержка, чтобы последний ondataavailable успел сработать */
    await new Promise(r => setTimeout(r, 100));

    if (chunksRef.current.length === 0) return;

    const mimeType = mr.mimeType || 'audio/webm';
    const ext = mimeType.includes('ogg') ? 'ogg' : mimeType.includes('mp4') ? 'mp4' : 'webm';
    const blob = new Blob(chunksRef.current, { type: mimeType });
    const file = new File([blob], `voice_${Date.now()}.${ext}`, { type: mimeType });
    chunksRef.current = [];

    setUploadingFile('голосовое…');
    try {
      const url = await uploadToStorage(file);
      const body = { content: '🎤 Голосовое сообщение', messageType: 'audio', mediaUrl: url, mediaName: file.name, duration: dur };
      const r = await fetch(`${API_BASE}/api/conversations/${convId}/messages`, {
        method:'POST', headers:{ 'Content-Type':'application/json', 'x-session-token': getST() },
        body: JSON.stringify(body),
      });
      if (r.ok) { const msg = await r.json(); setMessages(p => [...p, msg]); }
    } catch (e) {
      console.error('Voice upload failed:', e);
      alert('Не удалось отправить голосовое сообщение. Попробуйте ещё раз.');
    } finally {
      setUploadingFile(null);
    }
  };

  const cancelRecording = () => {
    if (mediaRef.current) { mediaRef.current.stop(); mediaRef.current.stream.getTracks().forEach(t=>t.stop()); mediaRef.current = null; }
    if (timerRef.current) { clearInterval(timerRef.current); timerRef.current = null; }
    setRecording(false); setRecSec(0);
  };

  /* ─── Video recording ─── */

  /* Sync live stream to preview <video> element whenever stream or overlay changes */
  useEffect(() => {
    if (videoOpen && vidPreviewRef.current && vidStreamRef.current) {
      vidPreviewRef.current.srcObject = vidStreamRef.current;
      vidPreviewRef.current.play().catch(() => {});
    }
  }, [videoOpen, videoTick]);

  const openVideoCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: camFacing, width: { ideal: 1280, min: 640 }, height: { ideal: 960, min: 480 } },
        audio: true,
      });
      vidStreamRef.current = stream;
      setVideoOpen(true);
      setVideoTick(t => t + 1);
    } catch {
      alert('Нет доступа к камере. Разрешите доступ в настройках браузера.');
    }
  };

  const closeVideoCamera = () => {
    vidStreamRef.current?.getTracks().forEach(t => t.stop());
    vidStreamRef.current = null;
    if (vidTimerRef.current) { clearInterval(vidTimerRef.current); vidTimerRef.current = null; }
    if (vidMediaRef.current) { try { vidMediaRef.current.stop(); } catch {} vidMediaRef.current = null; }
    vidChunksRef.current = [];
    setVideoOpen(false);
    setVideoRecording(false);
    setVideoSec(0);
  };

  const startVideoRec = () => {
    if (!vidStreamRef.current) return;
    const mime = ['video/mp4;codecs=avc1,mp4a.40.2','video/webm;codecs=vp9,opus','video/webm;codecs=vp8,opus','video/webm','video/mp4']
      .find(t => MediaRecorder.isTypeSupported(t)) ?? '';
    const opts = mime
      ? { mimeType: mime, videoBitsPerSecond: 1_200_000, audioBitsPerSecond: 64_000 }
      : {};
    const mr = new MediaRecorder(vidStreamRef.current, opts);
    vidChunksRef.current = [];
    mr.ondataavailable = e => { if (e.data.size > 0) vidChunksRef.current.push(e.data); };
    mr.start(200);
    vidMediaRef.current = mr;
    setVideoRecording(true);
    setVideoSec(0);
    vidTimerRef.current = setInterval(() => setVideoSec(s => s + 1), 1000);
  };

  const stopVideoRec = async () => {
    if (!vidMediaRef.current) return;
    const mr = vidMediaRef.current;
    const dur = videoSec;
    vidMediaRef.current = null;
    if (vidTimerRef.current) { clearInterval(vidTimerRef.current); vidTimerRef.current = null; }
    setVideoRecording(false);
    setVideoSec(0);
    setVideoOpen(false);

    await new Promise<void>(resolve => { mr.onstop = () => resolve(); mr.stop(); });
    await new Promise(r => setTimeout(r, 300));

    vidStreamRef.current?.getTracks().forEach(t => t.stop());
    vidStreamRef.current = null;

    const chunks = [...vidChunksRef.current];
    vidChunksRef.current = [];
    if (chunks.length === 0) { alert('Видео не было записано. Разрешите доступ к камере и микрофону и попробуйте ещё раз.'); return; }

    const mimeType = mr.mimeType || 'video/webm';
    const ext = mimeType.includes('mp4') ? 'mp4' : 'webm';
    const blob = new Blob(chunks, { type: mimeType });
    const file = new File([blob], `video_${Date.now()}.${ext}`, { type: mimeType });

    setUploadingFile('видеосообщение…');
    try {
      const url = await uploadToStorage(file);
      const body = { content: `videoMessage:${videoFrame}`, messageType: 'videoMessage', mediaUrl: url, mediaName: file.name, duration: dur };
      const r = await fetch(`${API_BASE}/api/conversations/${convId}/messages`, {
        method:'POST', headers:{ 'Content-Type':'application/json', 'x-session-token': getST() },
        body: JSON.stringify(body),
      });
      if (r.ok) { const msg = await r.json(); setMessages(p => [...p, msg]); }
    } catch { alert('Не удалось отправить видеосообщение. Попробуйте ещё раз.'); }
    finally { setUploadingFile(null); }
  };

  const flipCamera = async () => {
    const nf = camFacing === 'environment' ? 'user' : 'environment';
    setCamFacing(nf);
    vidStreamRef.current?.getTracks().forEach(t => t.stop());
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: nf, width: { ideal: 1280, min: 640 }, height: { ideal: 960, min: 480 } },
        audio: true,
      });
      vidStreamRef.current = stream;
      setVideoTick(t => t + 1);
    } catch {}
  };

  /* Filter contacts to exclude already-in-group participants */
  const participantHashes = new Set(participants.map(p => p.hash));
  participantHashes.add(myHash);
  const availableContacts = contacts.filter(c => !participantHashes.has(c.hash));

  return (
    <div style={{ position:'fixed', inset:0, background:C.bg, display:'flex', flexDirection:'column', zIndex:300 }}>

      <CompassBackTab onBack={onBack} accent={accent} label="← ПЕРЕПИСКИ" />

      {/* ── Header ── */}
      <div style={{ display:'flex', alignItems:'center', gap:10, padding:'10px 12px',
        background:'rgba(10,12,20,0.95)', backdropFilter:'blur(16px)',
        borderBottom:'1px solid rgba(255,255,255,0.07)', flexShrink:0 }}>

        {/* Avatar or Group icon */}
        {isGroup ? (
          <div style={{ width:44, height:44, borderRadius:'50%', background:`linear-gradient(135deg,${accent}44,${accent}22)`,
            border:`2px solid ${accent}66`, display:'flex', alignItems:'center', justifyContent:'center',
            fontSize:20, flexShrink:0 }}>👥</div>
        ) : (
          <motion.div whileTap={{ scale:0.9 }}
            onClick={() => onViewProfile && onViewProfile(otherHash)}
            style={{ width:44, height:44, borderRadius:'50%', overflow:'hidden', border:`2px solid ${accent}`, flexShrink:0,
              cursor: onViewProfile ? 'pointer' : 'default' }}>
            <Avatar32 info={otherInfo} accent={accent} />
          </motion.div>
        )}

        <div style={{ flex:1, minWidth:0 }}>
          {editingName ? (
            <div style={{ display:'flex', gap:6 }}>
              <input value={newGroupName} onChange={e => setNewGroupName(e.target.value)}
                onKeyDown={e => { if (e.key==='Enter') handleRenameGroup(); if (e.key==='Escape') setEditingName(false); }}
                placeholder={t.group_name_ph}
                style={{ flex:1, background:'rgba(255,255,255,0.1)', border:'1px solid rgba(255,255,255,0.2)',
                  borderRadius:8, padding:'4px 8px', color:'#fff', fontSize:13, outline:'none',
                  fontFamily:'"Montserrat",sans-serif' }} autoFocus />
              <button onClick={handleRenameGroup} style={{ background:accent, border:'none', borderRadius:6,
                color:'#000', fontWeight:700, fontSize:12, padding:'4px 8px', cursor:'pointer' }}>✓</button>
            </div>
          ) : (
            <>
              <div style={{ fontWeight:800, fontSize:15, fontFamily:'"Montserrat",sans-serif', color:'#fff',
                overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap',
                cursor: (isGroup || onViewProfile) ? 'pointer' : 'default' }}
                onClick={() => {
                  if (isGroup) { setNewGroupName(groupName); setEditingName(true); }
                  else if (onViewProfile) { onViewProfile(otherHash); }
                }}>
                {isGroup ? (groupName || 'Беседа') : otherInfo.name}
              </div>
              <div style={{ fontSize:11, color:'rgba(255,255,255,0.4)', fontFamily:'"Montserrat",sans-serif' }}>
                {isGroup ? `${participants.length} участников` : 'в сети'}
              </div>
            </>
          )}
        </div>

        {/* Action buttons */}
        {/* ── Кнопки звонка (только в 1:1 чатах) ── */}
        {!isGroup && (
          <>
            <motion.button whileTap={{ scale:0.88 }}
              onClick={() => call.startCall(otherHash, 'audio')}
              disabled={call.callState !== 'idle'}
              style={{ background:'rgba(34,197,94,0.15)', border:'1px solid rgba(34,197,94,0.35)',
                borderRadius:'50%', width:36, height:36, cursor: call.callState !== 'idle' ? 'not-allowed' : 'pointer',
                fontSize:18, display:'flex', alignItems:'center', justifyContent:'center',
                flexShrink:0, opacity: call.callState !== 'idle' ? 0.4 : 1 }}
              title={t.call_voice}>
              📞
            </motion.button>
            <motion.button whileTap={{ scale:0.88 }}
              onClick={() => call.startCall(otherHash, 'video')}
              disabled={call.callState !== 'idle'}
              style={{ background:'rgba(99,102,241,0.15)', border:'1px solid rgba(99,102,241,0.35)',
                borderRadius:'50%', width:36, height:36, cursor: call.callState !== 'idle' ? 'not-allowed' : 'pointer',
                fontSize:18, display:'flex', alignItems:'center', justifyContent:'center',
                flexShrink:0, opacity: call.callState !== 'idle' ? 0.4 : 1 }}
              title="Видеозвонок">
              🎥
            </motion.button>
          </>
        )}
        {/* Add participant */}
        <motion.button whileTap={{ scale:0.88 }}
          onClick={() => { loadContacts(); setShowAddModal(true); }}
          style={{ background:`${accent}22`, border:`1px solid ${accent}44`, borderRadius:'50%',
            width:36, height:36, cursor:'pointer', fontSize:16, display:'flex', alignItems:'center',
            justifyContent:'center', flexShrink:0, color:accent }}
          title="Добавить участника">
          👥
        </motion.button>

        {/* Members list (for groups) */}
        {isGroup && (
          <motion.button whileTap={{ scale:0.88 }}
            onClick={() => setShowMembers(s => !s)}
            style={{ background:'rgba(255,255,255,0.07)', border:'none', borderRadius:'50%', width:36, height:36,
              cursor:'pointer', fontSize:16, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}
            title="Участники">ℹ️</motion.button>
        )}
      </div>

      {/* Members panel (collapsible) */}
      {showMembers && isGroup && (
        <div style={{ background:'rgba(10,12,20,0.98)', borderBottom:'1px solid rgba(255,255,255,0.07)',
          padding:'10px 14px', display:'flex', flexDirection:'column', gap:6, flexShrink:0 }}>
          <div style={{ fontSize:10, fontWeight:900, color:'rgba(255,255,255,0.3)',
            letterSpacing:3, textTransform:'uppercase', marginBottom:4 }}>{t.members_label.toUpperCase()}</div>
          {participants.map(p => (
            <div key={p.hash} style={{ display:'flex', alignItems:'center', gap:10 }}>
              <div style={{ width:32, height:32, borderRadius:'50%', overflow:'hidden', border:`1.5px solid ${accent}44`, flexShrink:0 }}>
                <Avatar32 info={p.info} accent={accent} />
              </div>
              <div style={{ flex:1 }}>
                <div style={{ fontSize:13, fontWeight:700, color:'#fff' }}>{p.info.name}</div>
                {p.info.handle && <div style={{ fontSize:10, color:'rgba(255,255,255,0.4)' }}>@{p.info.handle}</div>}
              </div>
              {p.hash === myHash && <div style={{ fontSize:10, color:accent, fontWeight:700 }}>{t.you_label}</div>}
            </div>
          ))}
          {isGroup && (
            <motion.button whileTap={{ scale:0.95 }} onClick={handleLeaveGroup}
              style={{ marginTop:4, padding:'8px', borderRadius:8, border:'1px solid rgba(239,68,68,0.3)',
                background:'rgba(239,68,68,0.1)', color:'#ef4444', fontWeight:700, fontSize:12,
                cursor:'pointer', fontFamily:'"Montserrat",sans-serif' }}>
              {t.leave_chat_btn}
            </motion.button>
          )}
        </div>
      )}

      {/* ── Add Participant Modal ── */}
      {showAddModal && (
        <div style={{ position:'absolute', inset:0, zIndex:1000, background:'rgba(0,0,0,0.7)',
          display:'flex', alignItems:'flex-end', backdropFilter:'blur(4px)' }}
          onClick={e => { if (e.target === e.currentTarget) setShowAddModal(false); }}>
          <motion.div initial={{ y:300 }} animate={{ y:0 }} exit={{ y:300 }}
            style={{ width:'100%', background:'#0d1020', borderRadius:'24px 24px 0 0',
              padding:'20px 16px 32px', maxHeight:'70vh', display:'flex', flexDirection:'column',
              border:'1px solid rgba(255,255,255,0.1)' }}>
            <div style={{ display:'flex', alignItems:'center', marginBottom:16, gap:10 }}>
              <div style={{ fontSize:18, fontWeight:900, color:'#fff', flex:1,
                fontFamily:'"Montserrat",sans-serif' }}>
                {isGroup ? '➕ Добавить участника' : '👥 Создать беседу'}
              </div>
              <button onClick={() => setShowAddModal(false)}
                style={{ background:'none', border:'none', color:'rgba(255,255,255,0.5)', cursor:'pointer', fontSize:22, lineHeight:1 }}>✕</button>
            </div>
            {!isGroup && (
              <div style={{ fontSize:12, color:'rgba(255,255,255,0.45)', marginBottom:12, lineHeight:1.5,
                fontFamily:'"Montserrat",sans-serif' }}>
                Добавьте участника — переписка станет общей беседой
              </div>
            )}
            <div style={{ flex:1, overflowY:'auto' }}>
              {availableContacts.length === 0 ? (
                <div style={{ textAlign:'center', padding:'32px 0', color:'rgba(255,255,255,0.35)',
                  fontSize:13, fontFamily:'"Montserrat",sans-serif' }}>
                  <div style={{ fontSize:36, marginBottom:8 }}>🤷</div>
                  Нет доступных контактов<br/>
                  <span style={{ fontSize:11 }}>{t.follow_to_add}</span>
                </div>
              ) : (
                availableContacts.map(c => (
                  <div key={c.hash} style={{ display:'flex', alignItems:'center', gap:12,
                    padding:'10px 0', borderBottom:'1px solid rgba(255,255,255,0.05)' }}>
                    <div style={{ width:44, height:44, borderRadius:'50%', overflow:'hidden',
                      border:`1.5px solid ${accent}44`, flexShrink:0 }}>
                      <Avatar32 info={c.info} accent={accent} />
                    </div>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:14, fontWeight:700, color:'#fff',
                        overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{c.info.name}</div>
                      {c.info.handle && <div style={{ fontSize:11, color:'rgba(255,255,255,0.4)' }}>@{c.info.handle}</div>}
                    </div>
                    <motion.button whileTap={{ scale:0.92 }}
                      onClick={() => handleAddParticipant(c.hash)}
                      disabled={adding === c.hash}
                      style={{ padding:'8px 16px', borderRadius:100,
                        background: adding === c.hash ? 'rgba(255,255,255,0.1)' : `linear-gradient(135deg,${accent},${accent}bb)`,
                        border:'none', color: adding === c.hash ? 'rgba(255,255,255,0.5)' : '#000',
                        fontWeight:900, fontSize:13, cursor:'pointer', fontFamily:'"Montserrat",sans-serif',
                        flexShrink:0 }}>
                      {adding === c.hash ? '…' : '+ Добавить'}
                    </motion.button>
                  </div>
                ))
              )}
            </div>
          </motion.div>
        </div>
      )}

      {/* Messages */}
      <div style={{ flex:1, overflowY:'auto', padding:'16px 12px', display:'flex', flexDirection:'column', gap:4 }}>
        {messages.length === 0 && (
          <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', gap:16, padding:40, opacity:0.6 }}>
            <div style={{ fontSize:48 }}>💬</div>
            <div style={{ fontSize:15, color:'rgba(255,255,255,0.5)', textAlign:'center', fontFamily:'"Montserrat",sans-serif' }}>
              Здесь пока ничего нет…<br/><span style={{fontSize:12}}>Отправьте первое сообщение</span>
            </div>
          </div>
        )}
        {messages.map((m, i) => {
          const isMe = m.senderHash === myHash;
          const isSystem = m.messageType === 'system' || m.senderHash === '__system__';
          const showDate = i === 0 || new Date(m.createdAt).toDateString() !== new Date(messages[i-1].createdAt).toDateString();
          const showSenderName = isGroup && !isMe && !isSystem;
          const prevM = i > 0 ? messages[i-1] : null;
          const isSameAuthorAsPrev = prevM && prevM.senderHash === m.senderHash;

          return (
            <React.Fragment key={m.id}>
              {showDate && (
                <div style={{ textAlign:'center', fontSize:11, color:'rgba(255,255,255,0.3)', margin:'8px 0',
                  fontFamily:'"Montserrat",sans-serif' }}>
                  {new Date(m.createdAt).toLocaleDateString('ru',{day:'2-digit',month:'long'})}
                </div>
              )}
              {/* System message */}
              {isSystem ? (
                <div style={{ textAlign:'center', fontSize:11, color:'rgba(255,255,255,0.35)', margin:'6px 0',
                  padding:'4px 12px', fontFamily:'"Montserrat",sans-serif' }}>
                  — {m.content} —
                </div>
              ) : (
              <div style={{ display:'flex', flexDirection: isMe ? 'row-reverse' : 'row', gap:8, alignItems:'flex-end',
                marginTop: showSenderName && !isSameAuthorAsPrev ? 8 : 2 }}>
                {!isMe && (
                  <div
                    onClick={() => m.senderHash && onViewProfile && onViewProfile(m.senderHash)}
                    style={{ width:28, height:28, borderRadius:'50%', overflow:'hidden', flexShrink:0, marginBottom:2,
                      visibility: !isSameAuthorAsPrev ? 'visible' : 'hidden',
                      cursor: (m.senderHash && onViewProfile) ? 'pointer' : 'default' }}>
                    <Avatar32 info={m.author} accent={accent} />
                  </div>
                )}
                <div style={{ maxWidth:'72%', display:'flex', flexDirection:'column', alignItems: isMe ? 'flex-end' : 'flex-start' }}>
                  {showSenderName && !isSameAuthorAsPrev && (
                    <div
                      onClick={() => m.senderHash && onViewProfile && onViewProfile(m.senderHash)}
                      style={{ fontSize:10, fontWeight:700, color:accent, marginBottom:2,
                        fontFamily:'"Montserrat",sans-serif', paddingLeft:2,
                        cursor: (m.senderHash && onViewProfile) ? 'pointer' : 'default' }}>
                      {m.author.name}
                    </div>
                  )}
                  <div style={{
                    background: isMe ? accent : 'rgba(255,255,255,0.09)',
                    color: isMe ? '#000' : '#fff',
                    borderRadius: isMe ? '18px 18px 4px 18px' : '18px 18px 18px 4px',
                    padding: (m.messageType === 'image' || m.messageType === 'videoMessage') ? '4px' : '10px 14px',
                    maxWidth:'100%', wordBreak:'break-word',
                    border: isMe ? 'none' : '1px solid rgba(255,255,255,0.08)',
                  }}>
                    {m.messageType === 'image' && m.mediaUrl && (
                      <img src={m.mediaUrl} alt="" style={{ maxWidth:220, maxHeight:300, borderRadius:14, display:'block' }} />
                    )}
                    {m.messageType === 'gif' && m.mediaUrl && (
                      <img src={m.mediaUrl} alt="gif" style={{ maxWidth:220, borderRadius:14, display:'block' }} />
                    )}
                    {m.messageType === 'video' && m.mediaUrl && (
                      <video src={m.mediaUrl} controls style={{ maxWidth:220, maxHeight:300, borderRadius:14, display:'block' }} />
                    )}
                    {m.messageType === 'audio' && m.mediaUrl && (
                      <div style={{ display:'flex', alignItems:'center', gap:10, minWidth:180 }}>
                        <span style={{ fontSize:24 }}>🎤</span>
                        <audio controls src={m.mediaUrl} style={{ height:36, flex:1 }} />
                        {m.duration && <span style={{ fontSize:11, opacity:0.7 }}>{m.duration}с</span>}
                      </div>
                    )}
                    {m.messageType === 'videoMessage' && m.mediaUrl && (() => {
                      const dur = m.duration ?? 0;
                      const mm = String(Math.floor(dur/60)).padStart(2,'0');
                      const ss = String(dur%60).padStart(2,'0');
                      const frame: VFrame = (() => {
                        const c = m.content ?? '';
                        if (c.startsWith('videoMessage:')) return c.replace('videoMessage:','') as VFrame;
                        return 'filmstrip';
                      })();
                      const TimeBadge = () => (
                        <div style={{ position:'absolute', top:7, left:7,
                          background:'rgba(0,0,0,0.78)', borderRadius:6,
                          padding:'3px 7px', display:'flex', alignItems:'center', gap:5,
                          backdropFilter:'blur(6px)', zIndex:2 }}>
                          <span style={{ fontSize:10 }}>🎬</span>
                          <span style={{ fontSize:11, color:'#f59e0b', fontWeight:700,
                            fontFamily:'"Montserrat",sans-serif' }}>{mm}:{ss}</span>
                        </div>
                      );
                      const vid = (style: React.CSSProperties) => (
                        <video src={m.mediaUrl!} controls playsInline
                          style={{ display:'block', ...style }} />
                      );
                      if (frame === 'filmstrip') {
                        const HOLE = { width:8, height:8, borderRadius:2, background:'#060606', border:'1.5px solid #3a3a3a', flexShrink:0 as const };
                        const Holes = () => <div style={{ display:'flex', alignItems:'center', gap:5, padding:'0 6px' }}>{Array.from({length:9}).map((_,i) => <div key={i} style={HOLE}/>)}</div>;
                        return (
                          <div style={{ background:'#0d0d0d', border:'2px solid #2c2c2c', borderRadius:12, overflow:'hidden', maxWidth:220,
                            boxShadow:'0 6px 24px rgba(0,0,0,0.9)' }}>
                            <div style={{ background:'#1a1a1a', height:16, display:'flex', alignItems:'center' }}><Holes/></div>
                            <div style={{ position:'relative' }}>
                              {vid({ width:'100%', maxHeight:260, objectFit:'cover', background:'#000' })}
                              <TimeBadge/>
                            </div>
                            <div style={{ background:'#1a1a1a', height:16, display:'flex', alignItems:'center' }}><Holes/></div>
                          </div>
                        );
                      }
                      if (frame === 'retrotv') {
                        return (
                          <div style={{ background:'#c8b89a', borderRadius:18, padding:'10px 12px 14px',
                            maxWidth:230, boxShadow:'0 6px 24px rgba(0,0,0,0.7)', border:'2px solid #a89070' }}>
                            {/* Antenna */}
                            <div style={{ display:'flex', justifyContent:'center', gap:24, marginBottom:6 }}>
                              <div style={{ width:3, height:22, background:'#888', borderRadius:2, transform:'rotate(-12deg)', transformOrigin:'bottom' }}/>
                              <div style={{ width:3, height:22, background:'#888', borderRadius:2, transform:'rotate(12deg)', transformOrigin:'bottom' }}/>
                            </div>
                            {/* Screen */}
                            <div style={{ background:'#111', borderRadius:8, overflow:'hidden', border:'4px solid #7a6650',
                              boxShadow:'inset 0 0 18px rgba(0,0,0,0.9)', position:'relative' }}>
                              {vid({ width:'100%', maxHeight:170, objectFit:'cover', background:'#000', opacity:0.92 })}
                              {/* Scan lines */}
                              <div style={{ position:'absolute', inset:0, backgroundImage:'repeating-linear-gradient(0deg,transparent,transparent 3px,rgba(0,0,0,0.15) 3px,rgba(0,0,0,0.15) 4px)', pointerEvents:'none' }}/>
                              <TimeBadge/>
                            </div>
                            {/* Controls */}
                            <div style={{ display:'flex', justifyContent:'flex-end', alignItems:'center', gap:8, marginTop:8, paddingRight:4 }}>
                              <div style={{ width:14, height:14, borderRadius:'50%', background:'#7a6650', border:'2px solid #5a4535' }}/>
                              <div style={{ width:14, height:14, borderRadius:'50%', background:'#7a6650', border:'2px solid #5a4535' }}/>
                              <div style={{ fontSize:9, color:'#7a6650', fontFamily:'monospace', marginLeft:4 }}>CH 1</div>
                            </div>
                          </div>
                        );
                      }
                      if (frame === 'camera') {
                        return (
                          <div style={{ background:'#1c1c1c', borderRadius:14, padding:'8px', maxWidth:230,
                            boxShadow:'0 6px 24px rgba(0,0,0,0.8)', border:'2px solid #333' }}>
                            {/* Camera top bar */}
                            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'2px 4px 6px' }}>
                              <div style={{ width:16, height:16, borderRadius:'50%', background:'#111', border:'2px solid #444', display:'flex', alignItems:'center', justifyContent:'center' }}>
                                <div style={{ width:8, height:8, borderRadius:'50%', background:'#222', border:'1px solid #555' }}/>
                              </div>
                              <span style={{ fontSize:9, color:'rgba(255,255,255,0.3)', fontFamily:'monospace', letterSpacing:1 }}>SWAIP CAM</span>
                              <motion.div animate={{ opacity:[1,0.3,1] }} transition={{ repeat:Infinity, duration:1.2 }}
                                style={{ width:8, height:8, borderRadius:'50%', background:'#ef4444' }}/>
                            </div>
                            {/* Viewfinder with corner brackets */}
                            <div style={{ position:'relative', background:'#000', borderRadius:6, overflow:'hidden' }}>
                              {vid({ width:'100%', maxHeight:200, objectFit:'cover', background:'#000' })}
                              {/* Corners */}
                              {[{top:6,left:6},{top:6,right:6},{bottom:6,left:6},{bottom:6,right:6}].map((pos,i) => (
                                <div key={i} style={{ position:'absolute', ...pos, width:16, height:16,
                                  borderTop: (i<2)?'2px solid rgba(255,255,255,0.7)':'none',
                                  borderBottom: (i>=2)?'2px solid rgba(255,255,255,0.7)':'none',
                                  borderLeft: (i%2===0)?'2px solid rgba(255,255,255,0.7)':'none',
                                  borderRight: (i%2===1)?'2px solid rgba(255,255,255,0.7)':'none' }}/>
                              ))}
                              <TimeBadge/>
                            </div>
                          </div>
                        );
                      }
                      if (frame === 'camcorder') {
                        return (
                          <div style={{ background:'#111', borderRadius:12, padding:'8px 10px 10px', maxWidth:240,
                            boxShadow:'0 6px 24px rgba(0,0,0,0.8)', border:'2px solid #2a2a2a' }}>
                            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:6 }}>
                              <span style={{ fontSize:9, color:'rgba(255,255,255,0.5)', fontFamily:'monospace', letterSpacing:2 }}>■ VHS</span>
                              <div style={{ display:'flex', alignItems:'center', gap:5 }}>
                                <motion.div animate={{ opacity:[1,0,1] }} transition={{ repeat:Infinity, duration:0.9 }}
                                  style={{ width:7, height:7, borderRadius:'50%', background:'#ef4444' }}/>
                                <span style={{ fontSize:9, color:'#ef4444', fontFamily:'monospace', fontWeight:700 }}>REC</span>
                              </div>
                              <span style={{ fontSize:9, color:'rgba(255,255,255,0.3)', fontFamily:'monospace' }}>00:{mm}:{ss}</span>
                            </div>
                            <div style={{ position:'relative', background:'#000', borderRadius:4, overflow:'hidden' }}>
                              {vid({ width:'100%', maxHeight:155, objectFit:'cover', background:'#000' })}
                              <TimeBadge/>
                            </div>
                            <div style={{ display:'flex', justifyContent:'center', marginTop:7, gap:6 }}>
                              {Array.from({length:5}).map((_,i) => (
                                <div key={i} style={{ width:20, height:5, borderRadius:3, background:'rgba(255,255,255,0.06)', border:'1px solid rgba(255,255,255,0.1)' }}/>
                              ))}
                            </div>
                          </div>
                        );
                      }
                      if (frame === 'balloon') {
                        return (
                          <div style={{ display:'flex', flexDirection:'column', alignItems:'center', maxWidth:190 }}>
                            <div style={{ width:180, height:180, borderRadius:'50%', overflow:'hidden', position:'relative',
                              background:'linear-gradient(135deg,#7c3aed,#3b82f6,#06b6d4)',
                              padding:3, boxShadow:'0 6px 28px rgba(124,58,237,0.5)' }}>
                              <div style={{ width:'100%', height:'100%', borderRadius:'50%', overflow:'hidden', background:'#000', position:'relative' }}>
                                {vid({ width:'100%', height:'100%', objectFit:'cover', background:'#000' })}
                                <TimeBadge/>
                              </div>
                            </div>
                            {/* Balloon string */}
                            <svg width="20" height="30" viewBox="0 0 20 30" style={{ marginTop:-2 }}>
                              <path d="M10 2 Q5 15 10 28" stroke="rgba(255,255,255,0.4)" strokeWidth="1.5" fill="none" strokeLinecap="round"/>
                            </svg>
                          </div>
                        );
                      }
                      return null;
                    })()}
                    {m.messageType === 'file' && m.mediaUrl && (
                      <a href={m.mediaUrl} target="_blank" rel="noreferrer"
                        style={{ display:'flex', alignItems:'center', gap:10, color: isMe ? '#000' : '#fff', textDecoration:'none' }}>
                        <span style={{ fontSize:28 }}>{
                          m.mediaName?.endsWith('.pdf') ? '📄' : m.mediaName?.match(/\.(doc|docx)$/) ? '📝' : '📎'
                        }</span>
                        <div>
                          <div style={{ fontWeight:700, fontSize:13 }}>{m.mediaName || 'Файл'}</div>
                          <div style={{ fontSize:11, opacity:0.6 }}>{t.tap_to_open}</div>
                        </div>
                      </a>
                    )}
                    {m.messageType === 'text' && (() => {
                      /* Детектируем SWAIP-ссылку-приглашение */
                      const inviteMatch = m.content?.match(/(https?:\/\/[^\s]+\/([a-f0-9]{64})\/(pro|scene|krug|circle))/i);
                      if (inviteMatch) {
                        const inviteUrl  = inviteMatch[1];
                        const inviteHash = inviteMatch[2];
                        const inviteMode = inviteMatch[3].toLowerCase();
                        const modeLabel  = inviteMode === 'krug' || inviteMode === 'circle' ? 'Круг' : inviteMode === 'scene' ? 'Сцена' : 'Про';
                        const modeIcon   = inviteMode === 'krug' || inviteMode === 'circle' ? '🔵' : inviteMode === 'scene' ? '🎭' : '💼';
                        const isCircleInvite = inviteMode === 'krug' || inviteMode === 'circle';
                        /* Текст перед ссылкой (если есть) */
                        const textBefore = m.content.slice(0, inviteMatch.index).trim();
                        return (
                          <div style={{ fontFamily:'"Montserrat",sans-serif' }}>
                            {textBefore && (
                              <p style={{ margin:'0 0 8px', fontSize:13, lineHeight:1.5 }}>{textBefore}</p>
                            )}
                            {/* Карточка приглашения */}
                            <div style={{ background: isMe ? 'rgba(0,0,0,0.2)' : 'rgba(255,255,255,0.06)',
                              border:`1px solid ${isCircleInvite ? '#c9983a66' : '#60a5fa44'}`,
                              borderRadius:14, padding:'10px 12px', minWidth:180 }}>
                              <div style={{ display:'flex', alignItems:'center', gap:6, marginBottom:6 }}>
                                <span style={{ fontSize:16 }}>{modeIcon}</span>
                                <span style={{ fontSize:11, fontWeight:900, color: isCircleInvite ? '#c9983a' : '#60a5fa',
                                  letterSpacing:1, textTransform:'uppercase' }}>{t.invitation_label} · {modeLabel}</span>
                              </div>
                              <div style={{ fontSize:12, color:'rgba(255,255,255,0.6)', marginBottom:8, lineHeight:1.4 }}>
                                {isCircleInvite
                                  ? t.add_to_circle_hint
                                  : t.open_profile_hint}
                              </div>
                              {isCircleInvite ? (
                                /* Кнопка «Добавить в друзья» — создаёт взаимную подписку */
                                <SwaipInviteButton
                                  targetHash={inviteHash}
                                  inviteUrl={inviteUrl}
                                  myHash={myHash}
                                  accent={isMe ? '#000' : '#c9983a'}
                                  onViewProfile={onViewProfile}
                                />
                              ) : (
                                <motion.button whileTap={{ scale:0.95 }}
                                  onClick={() => onViewProfile ? onViewProfile(inviteHash) : window.open(inviteUrl, '_self')}
                                  style={{ width:'100%', padding:'8px', borderRadius:100, border:'none',
                                    background: isMe ? 'rgba(255,255,255,0.3)' : '#60a5fa22',
                                    color: isMe ? '#000' : '#60a5fa', fontWeight:800, fontSize:12,
                                    fontFamily:'"Montserrat",sans-serif', cursor:'pointer' }}>
                                  → Открыть профиль
                                </motion.button>
                              )}
                            </div>
                          </div>
                        );
                      }
                      return <span style={{ fontSize:15, lineHeight:1.5, fontFamily:'"Montserrat",sans-serif' }}>{m.content}</span>;
                    })()}
                  </div>
                  <div style={{ fontSize:10, color:'rgba(255,255,255,0.28)', marginTop:2,
                    fontFamily:'"Montserrat",sans-serif', paddingRight:4, paddingLeft:4 }}>
                    {formatMsgTime(m.createdAt)}{isMe && (m.isRead ? ' ✓✓' : ' ✓')}
                  </div>
                </div>
              </div>
              )}
            </React.Fragment>
          );
        })}
        <div ref={bottomRef} />
      </div>

      {/* Emoji panel */}
      {showEmoji && (
        <div style={{ background:'rgba(10,12,20,0.98)', borderTop:'1px solid rgba(255,255,255,0.07)',
          padding:'12px 12px 8px', display:'flex', flexWrap:'wrap', gap:6, maxHeight:160, overflowY:'auto' }}>
          {EMOJIS_CHAT.map(e => (
            <button key={e} onClick={() => { setInput(p => p+e); setShowEmoji(false); inputRef.current?.focus(); }}
              style={{ background:'none', border:'none', fontSize:22, cursor:'pointer', lineHeight:1, padding:4 }}>{e}</button>
          ))}
        </div>
      )}

      {/* ─── Camera overlay for video messages ─── */}
      <AnimatePresence>
      {videoOpen && (() => {
        const FRAMES: { id: VFrame; label: string; name: string }[] = [
          { id:'filmstrip', label:'🎞', name:'Лента' },
          { id:'retrotv',   label:'📺', name:'ТВ'    },
          { id:'camera',    label:'📷', name:'Камера'},
          { id:'camcorder', label:'🎥', name:'Кам'  },
          { id:'balloon',   label:'🎈', name:'Шарик' },
        ];
        const recLabel = `${String(Math.floor(videoSec/60)).padStart(2,'0')}:${String(videoSec%60).padStart(2,'0')}`;

        /* ─ Live viewfinder body (mirrors the chat frame style, minus time badge) ─ */
        const LiveView = () => {
          const videoEl = (
            <video
              ref={el => {
                vidPreviewRef.current = el;
                if (el && vidStreamRef.current && el.srcObject !== vidStreamRef.current) {
                  el.srcObject = vidStreamRef.current;
                  el.play().catch(() => {});
                }
              }}
              muted playsInline autoPlay
              style={{ display:'block', width:'100%', height:'100%', objectFit:'cover',
                transform: camFacing==='user' ? 'scaleX(-1)' : 'none' }} />
          );
          const recBorder = videoRecording && (
            <motion.div animate={{ opacity:[0.5,1,0.5] }} transition={{ repeat:Infinity, duration:0.9 }}
              style={{ position:'absolute', inset:0, border:'3px solid #ef4444', borderRadius:'inherit', pointerEvents:'none' }}/>
          );

          if (videoFrame === 'filmstrip') {
            const HOLE = { width:8, height:8, borderRadius:2, background:'#060606', border:'1.5px solid #3a3a3a', flexShrink:0 as const };
            const Holes = () => <div style={{ display:'flex', alignItems:'center', gap:5, padding:'0 6px' }}>{Array.from({length:9}).map((_,i)=><div key={i} style={HOLE}/>)}</div>;
            return (
              <div style={{ background:'#0d0d0d', border:'2px solid #2c2c2c', borderRadius:12, overflow:'hidden' }}>
                <div style={{ background:'#1a1a1a', height:16, display:'flex', alignItems:'center' }}><Holes/></div>
                <div style={{ position:'relative', aspectRatio:'3/4', background:'#000', overflow:'hidden' }}>{videoEl}{recBorder}</div>
                <div style={{ background:'#1a1a1a', height:16, display:'flex', alignItems:'center' }}><Holes/></div>
              </div>
            );
          }
          if (videoFrame === 'retrotv') return (
            <div style={{ background:'#c8b89a', borderRadius:18, padding:'10px 12px 14px', border:'2px solid #a89070' }}>
              <div style={{ display:'flex', justifyContent:'center', gap:24, marginBottom:6 }}>
                <div style={{ width:3, height:22, background:'#888', borderRadius:2, transform:'rotate(-12deg)', transformOrigin:'bottom' }}/>
                <div style={{ width:3, height:22, background:'#888', borderRadius:2, transform:'rotate(12deg)', transformOrigin:'bottom' }}/>
              </div>
              <div style={{ background:'#111', borderRadius:8, overflow:'hidden', border:'4px solid #7a6650',
                boxShadow:'inset 0 0 18px rgba(0,0,0,0.9)', position:'relative', aspectRatio:'4/3' }}>
                {videoEl}
                <div style={{ position:'absolute', inset:0, backgroundImage:'repeating-linear-gradient(0deg,transparent,transparent 3px,rgba(0,0,0,0.15) 3px,rgba(0,0,0,0.15) 4px)', pointerEvents:'none' }}/>
                {recBorder}
              </div>
              <div style={{ display:'flex', justifyContent:'flex-end', gap:8, marginTop:8, paddingRight:4 }}>
                <div style={{ width:14, height:14, borderRadius:'50%', background:'#7a6650', border:'2px solid #5a4535' }}/>
                <div style={{ width:14, height:14, borderRadius:'50%', background:'#7a6650', border:'2px solid #5a4535' }}/>
              </div>
            </div>
          );
          if (videoFrame === 'camera') return (
            <div style={{ background:'#1c1c1c', borderRadius:14, padding:'8px', border:'2px solid #333' }}>
              <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'2px 4px 6px' }}>
                <div style={{ width:16, height:16, borderRadius:'50%', background:'#111', border:'2px solid #444', display:'flex', alignItems:'center', justifyContent:'center' }}>
                  <div style={{ width:8, height:8, borderRadius:'50%', background:'#222', border:'1px solid #555' }}/>
                </div>
                <span style={{ fontSize:9, color:'rgba(255,255,255,0.3)', fontFamily:'monospace', letterSpacing:1 }}>SWAIP CAM</span>
                <motion.div animate={{ opacity:[1,0.2,1] }} transition={{ repeat:Infinity, duration:1.1 }}
                  style={{ width:8, height:8, borderRadius:'50%', background: videoRecording?'#ef4444':'#22c55e' }}/>
              </div>
              <div style={{ position:'relative', background:'#000', borderRadius:6, overflow:'hidden', aspectRatio:'3/4' }}>
                {videoEl}
                {[{top:6,left:6},{top:6,right:6},{bottom:6,left:6},{bottom:6,right:6}].map((pos,i)=>(
                  <div key={i} style={{ position:'absolute', ...pos, width:16, height:16,
                    borderTop:(i<2)?'2px solid rgba(255,255,255,0.7)':'none',
                    borderBottom:(i>=2)?'2px solid rgba(255,255,255,0.7)':'none',
                    borderLeft:(i%2===0)?'2px solid rgba(255,255,255,0.7)':'none',
                    borderRight:(i%2===1)?'2px solid rgba(255,255,255,0.7)':'none' }}/>
                ))}
                {recBorder}
              </div>
            </div>
          );
          if (videoFrame === 'camcorder') return (
            <div style={{ background:'#111', borderRadius:12, padding:'8px 10px 10px', border:'2px solid #2a2a2a' }}>
              <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:6 }}>
                <span style={{ fontSize:9, color:'rgba(255,255,255,0.5)', fontFamily:'monospace', letterSpacing:2 }}>■ VHS</span>
                <div style={{ display:'flex', alignItems:'center', gap:5 }}>
                  {videoRecording && <motion.div animate={{ opacity:[1,0,1] }} transition={{ repeat:Infinity, duration:0.7 }}
                    style={{ width:7, height:7, borderRadius:'50%', background:'#ef4444' }}/>}
                  <span style={{ fontSize:9, color: videoRecording?'#ef4444':'rgba(255,255,255,0.3)', fontFamily:'monospace', fontWeight:700 }}>
                    {videoRecording?'REC':'STBY'}
                  </span>
                </div>
                <span style={{ fontSize:9, color:'rgba(255,255,255,0.3)', fontFamily:'monospace' }}>{recLabel}</span>
              </div>
              <div style={{ position:'relative', background:'#000', borderRadius:4, overflow:'hidden', aspectRatio:'16/9' }}>{videoEl}{recBorder}</div>
              <div style={{ display:'flex', justifyContent:'center', marginTop:7, gap:6 }}>
                {Array.from({length:5}).map((_,i)=>(
                  <div key={i} style={{ width:20, height:5, borderRadius:3, background:'rgba(255,255,255,0.06)', border:'1px solid rgba(255,255,255,0.1)' }}/>
                ))}
              </div>
            </div>
          );
          if (videoFrame === 'balloon') return (
            <div style={{ display:'flex', flexDirection:'column', alignItems:'center' }}>
              <div style={{ width:220, height:220, borderRadius:'50%', overflow:'hidden', position:'relative',
                background:'linear-gradient(135deg,#7c3aed,#3b82f6,#06b6d4)', padding:3 }}>
                <div style={{ width:'100%', height:'100%', borderRadius:'50%', overflow:'hidden', background:'#000', position:'relative' }}>
                  {videoEl}{recBorder}
                </div>
              </div>
              <svg width="20" height="24" viewBox="0 0 20 24" style={{ marginTop:-2 }}>
                <path d="M10 2 Q5 12 10 22" stroke="rgba(255,255,255,0.4)" strokeWidth="1.5" fill="none" strokeLinecap="round"/>
              </svg>
            </div>
          );
          return null;
        };

        return (
          <motion.div initial={{ opacity:0 }} animate={{ opacity:1 }} exit={{ opacity:0 }}
            style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.92)', zIndex:200,
              display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center',
              padding:'16px', paddingTop:'calc(16px + env(safe-area-inset-top,0px))',
              paddingBottom:'calc(16px + env(safe-area-inset-bottom,0px))', overflow:'hidden' }}>

            {/* Card */}
            <motion.div initial={{ scale:0.92, opacity:0 }} animate={{ scale:1, opacity:1 }} transition={{ type:'spring', stiffness:320, damping:28 }}
              style={{ width:'100%', maxWidth:340, background:'rgba(15,17,28,0.98)',
                borderRadius:24, padding:'16px 16px 20px', border:'1px solid rgba(255,255,255,0.1)',
                boxShadow:'0 24px 80px rgba(0,0,0,0.95)', display:'flex', flexDirection:'column', gap:12 }}>

              {/* Header */}
              <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between' }}>
                <motion.button whileTap={{scale:0.88}} onClick={closeVideoCamera}
                  style={{ background:'rgba(255,255,255,0.08)', border:'none', borderRadius:'50%',
                    width:38, height:38, cursor:'pointer', fontSize:16, display:'flex',
                    alignItems:'center', justifyContent:'center', color:'#fff' }}>✕</motion.button>

                {videoRecording ? (
                  <div style={{ display:'flex', alignItems:'center', gap:7, background:'rgba(239,68,68,0.15)',
                    borderRadius:20, padding:'5px 12px', border:'1px solid rgba(239,68,68,0.4)' }}>
                    <motion.div animate={{ scale:[1,1.4,1] }} transition={{ repeat:Infinity, duration:0.75 }}
                      style={{ width:8, height:8, borderRadius:'50%', background:'#ef4444' }}/>
                    <span style={{ color:'#ef4444', fontWeight:700, fontSize:13,
                      fontFamily:'"Montserrat",sans-serif' }}>{recLabel}</span>
                  </div>
                ) : (
                  <span style={{ color:'rgba(255,255,255,0.65)', fontSize:13,
                    fontFamily:'"Montserrat",sans-serif', fontWeight:600 }}>{t.video_message}</span>
                )}

                <motion.button whileTap={{scale:0.88}} onClick={flipCamera} disabled={videoRecording}
                  style={{ background:'rgba(255,255,255,0.08)', border:'none', borderRadius:'50%',
                    width:38, height:38, cursor: videoRecording?'not-allowed':'pointer', fontSize:18,
                    display:'flex', alignItems:'center', justifyContent:'center',
                    opacity: videoRecording ? 0.4 : 1 }}>🔄</motion.button>
              </div>

              {/* Frame picker */}
              {!videoRecording && (
                <div style={{ display:'flex', gap:8, justifyContent:'center' }}>
                  {FRAMES.map(f => (
                    <motion.button key={f.id} whileTap={{scale:0.88}} onClick={() => setVideoFrame(f.id)}
                      style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:3,
                        background: videoFrame===f.id ? 'rgba(255,255,255,0.14)' : 'rgba(255,255,255,0.05)',
                        border: videoFrame===f.id ? '1.5px solid rgba(255,255,255,0.4)' : '1.5px solid rgba(255,255,255,0.1)',
                        borderRadius:12, padding:'6px 8px', cursor:'pointer', minWidth:48 }}>
                      <span style={{ fontSize:18 }}>{f.label}</span>
                      <span style={{ fontSize:9, color: videoFrame===f.id?'#fff':'rgba(255,255,255,0.4)',
                        fontFamily:'"Montserrat",sans-serif', fontWeight:600 }}>{f.name}</span>
                    </motion.button>
                  ))}
                </div>
              )}

              {/* Live viewfinder */}
              <div style={{ borderRadius:16, overflow:'hidden' }}>
                <LiveView />
              </div>

              {/* Record button */}
              <div style={{ display:'flex', justifyContent:'center', marginTop:4 }}>
                {videoRecording ? (
                  <motion.button whileTap={{scale:0.9}} onClick={stopVideoRec}
                    style={{ width:66, height:66, borderRadius:'50%', border:'4px solid #fff',
                      background:'#ef4444', cursor:'pointer', display:'flex', alignItems:'center',
                      justifyContent:'center', fontSize:24, boxShadow:'0 0 0 6px rgba(239,68,68,0.3)' }}>⬛</motion.button>
                ) : (
                  <motion.button whileTap={{scale:0.9}} onClick={startVideoRec}
                    style={{ width:66, height:66, borderRadius:'50%', border:'4px solid #fff',
                      background:'#ef4444', cursor:'pointer', display:'flex', alignItems:'center',
                      justifyContent:'center', boxShadow:'0 0 0 6px rgba(239,68,68,0.22)' }}>
                    <div style={{ width:26, height:26, borderRadius:'50%', background:'#fff' }}/>
                  </motion.button>
                )}
              </div>
            </motion.div>
          </motion.div>
        );
      })()}
      </AnimatePresence>

      {/* File uploading indicator */}
      {uploadingFile && (
        <div style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 16px',
          background:'rgba(10,12,20,0.97)', borderTop:'1px solid rgba(255,255,255,0.07)',
          flexShrink:0 }}>
          <motion.div animate={{ rotate:360 }} transition={{ repeat:Infinity, duration:0.9, ease:'linear' }}
            style={{ width:16, height:16, borderRadius:'50%', border:`2px solid ${accent}`, borderTopColor:'transparent', flexShrink:0 }} />
          <span style={{ fontSize:13, color:'rgba(255,255,255,0.7)', fontFamily:'"Montserrat",sans-serif',
            overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', flex:1 }}>
            Загрузка: {uploadingFile}
          </span>
        </div>
      )}

      {/* Input bar */}
      {recording ? (
        <div style={{ display:'flex', alignItems:'center', gap:12, padding:'12px 16px',
          background:'rgba(10,12,20,0.97)', borderTop:'1px solid rgba(255,255,255,0.07)', flexShrink:0 }}>
          <motion.button whileTap={{scale:0.88}} onClick={cancelRecording}
            style={{ background:'rgba(239,68,68,0.15)', border:'1px solid rgba(239,68,68,0.3)', borderRadius:'50%',
              width:44, height:44, cursor:'pointer', fontSize:20, display:'flex', alignItems:'center', justifyContent:'center' }}>🗑</motion.button>
          <div style={{ flex:1, display:'flex', alignItems:'center', gap:10 }}>
            <motion.div animate={{ scale:[1,1.2,1] }} transition={{ repeat:Infinity, duration:0.8 }}
              style={{ width:10, height:10, borderRadius:'50%', background:'#ef4444' }} />
            <span style={{ color:'#ef4444', fontFamily:'"Montserrat",sans-serif', fontWeight:700, fontSize:14 }}>
              {Math.floor(recSec/60).toString().padStart(2,'0')}:{(recSec%60).toString().padStart(2,'0')}
            </span>
            <span style={{ fontSize:12, color:'rgba(255,255,255,0.4)' }}>{t.recording}</span>
          </div>
          <motion.button whileTap={{scale:0.88}} onClick={stopRecording}
            style={{ background:accent, border:'none', borderRadius:'50%', width:44, height:44,
              cursor:'pointer', fontSize:20, display:'flex', alignItems:'center', justifyContent:'center' }}>✅</motion.button>
        </div>
      ) : (
        <div style={{ display:'flex', alignItems:'center', gap:6, padding:'8px 10px',
          paddingBottom:'calc(8px + env(safe-area-inset-bottom,0px))',
          background:'rgba(10,12,20,0.97)', borderTop:'1px solid rgba(255,255,255,0.07)', flexShrink:0,
          boxSizing:'border-box', width:'100%' }}>
          <motion.button whileTap={{scale:0.88}} onClick={() => setShowEmoji(s => !s)}
            style={{ background:'rgba(255,255,255,0.07)', border:'none', borderRadius:'50%', width:36, height:36,
              cursor:'pointer', fontSize:18, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>😊</motion.button>

          <input ref={inputRef} value={input} onChange={e => setInput(e.target.value)}
            onKeyDown={e => { if (e.key==='Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); } }}
            placeholder={t.message_ph}
            style={{ flex:1, minWidth:0, background:'rgba(255,255,255,0.08)', border:'1px solid rgba(255,255,255,0.1)',
              borderRadius:20, padding:'9px 14px', color:'#fff', fontSize:14,
              fontFamily:'"Montserrat",sans-serif', outline:'none' }} />

          <label style={{ background:'rgba(255,255,255,0.07)', border:'none', borderRadius:'50%', width:36, height:36,
            cursor:'pointer', fontSize:17, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
            📎
            <input type="file" style={{ display:'none' }} multiple
              accept="image/*,video/*,audio/*,.pdf,.doc,.docx,.gif"
              onChange={e => { Array.from(e.target.files||[]).forEach(f => handleFile(f)); e.target.value=''; }} />
          </label>

          {/* 🎥 🎙 🔗 — только когда нет текста */}
          {!input.trim() && (
            <>
              <motion.button whileTap={{scale:0.88}} onClick={openVideoCamera}
                style={{ background:'rgba(239,68,68,0.12)', border:'1.5px solid rgba(239,68,68,0.35)',
                  borderRadius:'50%', width:33, height:33, cursor:'pointer', fontSize:15,
                  display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>🎥</motion.button>
              <motion.button
                onMouseDown={startRecording} onMouseUp={stopRecording}
                onTouchStart={startRecording} onTouchEnd={stopRecording}
                whileTap={{ scale:0.88 }}
                style={{ background:'rgba(59,130,246,0.15)', border:'1.5px solid rgba(59,130,246,0.4)',
                  borderRadius:'50%', width:33, height:33, cursor:'pointer', fontSize:15,
                  display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0,
                  color:'#3b82f6' }}>🎙</motion.button>
              {/* Кнопка «Пригласить в Круг» */}
              <motion.button whileTap={{scale:0.88}}
                title="Отправить ссылку-приглашение в Круг"
                onClick={() => {
                  const link = `${window.location.origin}/${myHash}/krug`;
                  setInput(`Приглашаю тебя в мой Круг на SWAIP: ${link}`);
                  setTimeout(() => inputRef.current?.focus(), 50);
                }}
                style={{ background:'rgba(201,152,58,0.15)', border:'1.5px solid rgba(201,152,58,0.4)',
                  borderRadius:'50%', width:33, height:33, cursor:'pointer', fontSize:15,
                  display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>🔗</motion.button>
            </>
          )}

          {/* ➤ Отправить — ВСЕГДА видна */}
          <motion.button
            whileTap={{ scale: 0.88 }}
            onClick={handleSend}
            disabled={sending}
            style={{
              background: input.trim() ? accent : 'rgba(255,255,255,0.12)',
              border: input.trim() ? 'none' : '1.5px solid rgba(255,255,255,0.2)',
              borderRadius:'50%',
              width: input.trim() ? 40 : 36,
              height: input.trim() ? 40 : 36,
              cursor:'pointer', fontSize:18,
              display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0,
              opacity: sending ? 0.6 : 1,
              transition: 'background 0.2s, width 0.15s, height 0.15s',
            }}>➤</motion.button>
        </div>
      )}
    </div>
  );
}

/* ─── Conversations List ─── */
function MessagesScreen({ myHash, accent, onBack, openChatWith, onViewProfile }:
  { myHash: string; accent: string; onBack: () => void; openChatWith?: { hash: string; info: ConvUser }; onViewProfile?: (hash: string) => void }) {
  const { t } = useLang();
  const C = { bg:'#0a0c14', card:'rgba(255,255,255,0.04)', border:'rgba(255,255,255,0.07)', sub:'rgba(255,255,255,0.4)' };
  const [conversations, setConversations] = useState<ConvItem[]>([]);
  const [loading,       setLoading]       = useState(true);
  const [activeConv,    setActiveConv]    = useState<{ id:number; otherHash:string; otherInfo:ConvUser; isGroup:boolean; groupName:string|null; participants:GroupParticipant[] }|null>(null);

  const loadConversations = async () => {
    try {
      const r = await fetch(`${API_BASE}/api/conversations`, { headers: { 'x-session-token': getST() } });
      if (r.ok) { const { conversations: cs } = await r.json(); setConversations(cs ?? []); }
    } catch {}
    setLoading(false);
  };

  useEffect(() => { loadConversations(); }, []);

  /* Auto-open chat when openChatWith is provided */
  useEffect(() => {
    if (!openChatWith) return;
    const startChat = async () => {
      try {
        const r = await fetch(`${API_BASE}/api/conversations`, {
          method:'POST', headers:{ 'Content-Type':'application/json', 'x-session-token': getST() },
          body: JSON.stringify({ otherHash: openChatWith.hash }),
        });
        if (r.ok) {
          const { conversation: c } = await r.json();
          setActiveConv({ id: c.id, otherHash: openChatWith.hash, otherInfo: openChatWith.info, isGroup: false, groupName: null, participants: [] });
        }
      } catch {}
    };
    startChat();
  }, [openChatWith?.hash]);

  if (activeConv) return (
    <ChatScreen convId={activeConv.id} otherHash={activeConv.otherHash} otherInfo={activeConv.otherInfo}
      myHash={myHash} accent={accent}
      isGroup={activeConv.isGroup} groupName={activeConv.groupName} participants={activeConv.participants}
      onBack={() => { setActiveConv(null); loadConversations(); }}
      onViewProfile={onViewProfile} />
  );

  return (
    <div style={{ position:'fixed', inset:0, background:C.bg, display:'flex', flexDirection:'column', zIndex:100 }}>
      <CompassBackTab onBack={onBack} accent="#3b82f6" />
      {/* Header */}
      <div style={{ display:'flex', alignItems:'center', gap:12, padding:'12px 16px',
        background:'rgba(10,12,20,0.95)', backdropFilter:'blur(16px)',
        borderBottom:'1px solid rgba(255,255,255,0.07)', flexShrink:0 }}>
        <div>
          <p style={{ margin:0, fontWeight:900, fontSize:18, fontFamily:'"Montserrat",sans-serif',
            background:'linear-gradient(90deg,#60a5fa,#a78bfa)', WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent' }}>
            {t.messages_header}
          </p>
          <p style={{ margin:0, fontSize:11, color:'rgba(255,255,255,0.4)', fontFamily:'"Montserrat",sans-serif' }}>
            {t.messages_subtitle}
          </p>
        </div>
      </div>

      <div style={{ flex:1, overflowY:'auto' }}>
        {loading && (
          <div style={{ display:'flex', justifyContent:'center', alignItems:'center', height:200 }}>
            <div style={{ width:28, height:28, borderRadius:'50%', border:`3px solid ${accent}`, borderTopColor:'transparent' }} />
          </div>
        )}

        {!loading && conversations.length === 0 && (
          <div style={{ display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center',
            gap:16, padding:60 }}>
            <div style={{ fontSize:56 }}>💬</div>
            <div style={{ fontSize:16, fontWeight:800, color:'#fff', fontFamily:'"Montserrat",sans-serif', textAlign:'center' }}>
              {t.no_chats}
            </div>
            <div style={{ fontSize:13, color:'rgba(255,255,255,0.5)', textAlign:'center', lineHeight:1.6, fontFamily:'"Montserrat",sans-serif', maxWidth:280 }}>
              {t.no_chats_hint}
            </div>
            <motion.button whileTap={{ scale:0.96 }} onClick={onBack}
              style={{ marginTop:8, padding:'12px 28px', borderRadius:100, border:'none',
                background:`linear-gradient(135deg, ${accent}, ${accent}bb)`,
                color:'#000', fontWeight:900, fontSize:14, cursor:'pointer',
                fontFamily:'"Montserrat",sans-serif' }}>
              {'🔍 '+t.go_to_search}
            </motion.button>
          </div>
        )}

        {conversations.map(c => {
          const isGroup = c.type === 'group';
          const displayName = isGroup ? (c.name || 'Беседа') : c.otherInfo.name;
          const subLabel = isGroup ? `${c.participants.length} участников` : (c.otherInfo.handle ? `@${c.otherInfo.handle}` : '');
          return (
          <motion.div key={c.id} whileTap={{ scale:0.98 }}
            onClick={() => setActiveConv({ id:c.id, otherHash:c.otherHash, otherInfo:c.otherInfo, isGroup, groupName: c.name ?? null, participants: c.participants })}
            style={{ display:'flex', alignItems:'center', gap:14, padding:'14px 16px',
              borderBottom:'1px solid rgba(255,255,255,0.05)', cursor:'pointer', position:'relative' }}>
            {/* Avatar */}
            {isGroup ? (
              <div style={{ width:54, height:54, borderRadius:'50%', flexShrink:0,
                background:`linear-gradient(135deg,${accent}33,${accent}11)`,
                border:`2px solid ${accent}44`,
                display:'flex', alignItems:'center', justifyContent:'center', fontSize:24 }}>👥</div>
            ) : (
              <div style={{ width:54, height:54, borderRadius:'50%', overflow:'hidden', flexShrink:0,
                border:`2px solid ${accent}44` }}>
                <Avatar32 info={c.otherInfo} accent={accent} />
              </div>
            )}
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:2 }}>
                <span style={{ fontWeight:800, fontSize:15, color:'#fff', fontFamily:'"Montserrat",sans-serif',
                  overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', maxWidth:'70%' }}>
                  {displayName}
                </span>
                <span style={{ fontSize:11, color:'rgba(255,255,255,0.35)', flexShrink:0 }}>
                  {c.lastMessage ? formatMsgTime(c.lastMessage.createdAt) : ''}
                </span>
              </div>
              {subLabel && (
                <div style={{ fontSize:11, color:accent, fontFamily:'"Montserrat",sans-serif',
                  marginBottom:2, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
                  {subLabel}
                </div>
              )}
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                <span style={{ fontSize:13, color:'rgba(255,255,255,0.45)', overflow:'hidden',
                  textOverflow:'ellipsis', whiteSpace:'nowrap', flex:1, fontFamily:'"Montserrat",sans-serif' }}>
                  {getMsgPreview(c.lastMessage)}
                </span>
                {c.unreadCount > 0 && (
                  <div style={{ background:accent, borderRadius:'50%', minWidth:20, height:20, fontSize:11,
                    display:'flex', alignItems:'center', justifyContent:'center', fontWeight:800,
                    color:'#000', padding:'0 5px', marginLeft:8, flexShrink:0 }}>
                    {c.unreadCount}
                  </div>
                )}
              </div>
            </div>
          </motion.div>
          );
        })}
      </div>
    </div>
  );
}

/* ─── Unread count badge for nav ─── */
function useUnreadConversations(myHash: string) {
  const [convs, setConvs] = useState<ConvItem[]>([]);
  useEffect(() => {
    if (!myHash) return;
    const check = async () => {
      try {
        const r = await fetch(`${API_BASE}/api/conversations`, { headers: { 'x-session-token': getST() } });
        if (r.ok) {
          const { conversations: cs } = await r.json();
          setConvs(cs ?? []);
        }
      } catch {}
    };
    check();
    const t = setInterval(check, 8000);
    return () => clearInterval(t);
  }, [myHash]);
  return convs;
}

